INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst wants to connect to a data source that automatically queries the underlying database every time a view is loaded, always reflecting the most current data. Which connection type should the analyst choose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Extract connection (.hyper file)"},{"id":"b","text":"Live connection"},{"id":"c","text":"Blended connection"},{"id":"d","text":"Published data source with incremental refresh"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Live connection queries the underlying data source in real time every time a view is loaded, ensuring the analyst always sees the most current data. An Extract (.hyper file) is an in-memory snapshot taken at a point in time and must be refreshed to reflect new data. Blending is a multi-source technique, not a connection type in this sense. A published data source with incremental refresh still uses an Extract, so it is not truly real-time.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau – Live vs Extract Connections"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst wants to connect to a data source that automatically queries the underlying database every time a view is loaded, always reflecting the most current data. Which connection type should the analyst choose?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
