INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to combine two Excel sheets that have identical column structures into a single logical table within Tableau Desktop's Data Source page. Which operation achieves this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Inner Join"},{"id":"b","text":"Relationship"},{"id":"c","text":"Union"},{"id":"d","text":"Data Blend"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A Union stacks tables that share the same column structure, appending rows from one table beneath the other. An Inner Join combines columns based on a matching key and does not simply stack rows. A Relationship links two logical tables and preserves their separate context. Data Blend operates across multiple connections at the view level. Per the source material, 'Unions combine tables with the same columns.'$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/union.htm","label":"Tableau – Union Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst needs to combine two Excel sheets that have identical column structures into a single logical table within Tableau Desktop's Data Source page. Which operation achieves this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst observes an asterisk (*) displayed in a cell when using data from a secondary data source in a blended view. What does this asterisk indicate?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The field contains a null value in the secondary source"},{"id":"b","text":"The linking field is not enabled for the blend"},{"id":"c","text":"Multiple values exist in the secondary source for that row in the primary source"},{"id":"d","text":"The secondary data source requires a password to access"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Per the source material, an asterisk ('*') in a blended view cell indicates that multiple values exist in the secondary source for a given row in the primary source — the blend cannot resolve the many-to-one relationship into a single value. It does not represent nulls, authentication issues, or a disabled linking field.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/multipleconnections_troubleshooting.htm","label":"Tableau – Troubleshoot Data Blending"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst observes an asterisk (*) displayed in a cell when using data from a secondary data source in a blended view. What does this asterisk indicate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau Desktop, which join type returns ALL rows from the left table and only matching rows from the right table, filling non-matching right-table fields with null?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Inner Join"},{"id":"b","text":"Right Join"},{"id":"c","text":"Left Join"},{"id":"d","text":"Full Outer Join"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A Left Join preserves every row from the left table; rows in the right table that have no match produce null values in the result set. An Inner Join returns only rows with matching keys in both tables. A Right Join preserves all rows from the right table. A Full Outer Join preserves all rows from both tables, filling nulls where no match exists on either side.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/joining_tables.htm","label":"Tableau – Join Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau Desktop, which join type returns ALL rows from the left table and only matching rows from the right table, filling non-matching right-table fields with null?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau developer needs to connect to data stored in two DIFFERENT database systems (SQL Server and Snowflake) and combine them within a single Tableau data source using join logic. Which feature supports this requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Wildcard Union"},{"id":"b","text":"Cross-database Join"},{"id":"c","text":"Data Blending"},{"id":"d","text":"Tableau Prep Aggregate step"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Cross-database joins allow joining tables from different connections within a single Tableau data source, as described in the source material. Data Blending also combines multiple sources but operates at the view level using aggregated secondary data, not via physical join logic. A Wildcard Union merges files matching a pattern from the same source. A Tableau Prep Aggregate step changes granularity within a Prep flow, not across databases at the Tableau Desktop data source level.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/joining_tables.htm#cross-database-joins","label":"Tableau – Join Data from Different Databases"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau developer needs to connect to data stored in two DIFFERENT database systems (SQL Server and Snowflake) and combine them within a single Tableau data source using join logic. Which feature supports this requirement?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst connects to several monthly CSV files stored in a folder. All files follow the naming convention 'Sales_YYYY_MM.csv'. They want Tableau to automatically include any new CSV files added to the folder that match this pattern. Which feature should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Manual Union"},{"id":"b","text":"Wildcard Union"},{"id":"c","text":"Cross-database Join"},{"id":"d","text":"Incremental Extract Refresh"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Wildcard Union automatically includes files that match a specified naming pattern, so any new files added to the folder matching 'Sales_*.csv' will be picked up without manual intervention. A Manual Union requires explicitly selecting each table/file. A Cross-database Join combines different database connections. Incremental Extract Refresh updates an existing Extract with new rows but does not automatically discover new files.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/union.htm#wildcard","label":"Tableau – Union Your Data (Wildcard Union)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
