         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/split.htm","label":"Tableau – Split a Field into Multiple Fields"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
