INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to add a filter that lets viewers of a published dashboard filter all worksheets connected to the same data source simultaneously. Which approach best achieves this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Apply the filter to only one worksheet and set it to 'All Using Related Data Sources'"},{"id":"b","text":"Add a separate filter to each worksheet manually"},{"id":"c","text":"Use a FIXED LOD expression to replicate filtering logic"},{"id":"d","text":"Change every worksheet to use a context filter"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Tableau allows a filter to be applied to all worksheets that use the same or related data source by right-clicking the filter and choosing 'Apply to Worksheets > All Using Related Data Sources'. This avoids configuring each sheet individually. FIXED LOD does not filter, adding filters to each worksheet separately is inefficient, and context filters affect order of operations but don't automatically propagate. The source notes filters can be set to 'Apply to: only this worksheet, all using related data sources, etc.'$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/filtering_global.htm","label":"Tableau Filter to Multiple Worksheets"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P1'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to add a filter that lets viewers of a published dashboard filter all worksheets connected to the same data source simultaneously. Which approach best achieves this?$patch$);

