  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst has a dataset with millions of rows and needs to sample a representative subset for exploratory visual analysis in Tableau without modifying the underlying data source. Which Tableau feature enables this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A calculated field contains the expression: ZN(SUM([Sales])) - LOOKUP(ZN(SUM([Sales])), -1). What does this expression compute?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The cumulative sum of sales from the first row to the current row"},{"id":"b","text":"The difference in sales between the current period and the immediately preceding period"},{"id":"c","text":"The percentage change in sales relative to the prior period"},{"id":"d","text":"The average of all sales values in the current partition"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$LOOKUP(expression, -1) retrieves the value from the previous row in the table calculation partition. Subtracting that prior value from the current value gives the period-over-period difference (delta). ZN() replaces NULL with zero to handle edge cases. The result is a simple absolute difference, not cumulative (which would use RUNNING_SUM), not a percentage change (which would divide by the LOOKUP value), and not an average (which would use WINDOW_AVG).$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_tablecalculation.htm#LOOKUP","label":"Tableau Help – LOOKUP Function"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A calculated field contains the expression: ZN(SUM([Sales])) - LOOKUP(ZN(SUM([Sales])), -1). What does this expression compute?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau, which filter type is evaluated LAST in the order of operations, meaning it can reference aggregated results but may slow query performance if overused?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Extract filter"},{"id":"b","text":"Context filter"},{"id":"c","text":"Dimension filter"},{"id":"d","text":"Table calculation filter"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$Tableau's order of operations for filters is: Extract Filters → Data Source Filters → Context Filters → Dimension/Measure Filters → Table Calculation Filters. Table calculation filters are evaluated last because they operate on the already-aggregated and computed view data. This means they can filter based on computed values, but since all data is fetched and computed first, they can impact performance. Extract filters are applied earliest, context filters create a temporary table, and dimension filters are applied during query execution.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/filter_order_of_operations.htm","label":"Tableau Help – Tableau Order of Operations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau, which filter type is evaluated LAST in the order of operations, meaning it can reference aggregated results but may slow query performance if overused?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to find customers whose individual order total is above the average order total for their respective region. Which Tableau expression type is best suited for this analysis?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A WINDOW_AVG table calculation comparing each row to the window average"},{"id":"b","text":"An EXCLUDE LOD expression to compute the region average, then a calculated field comparison"},{"id":"c","text":"A FIXED LOD expression to compute the average order total per region, then compare individual orders"},{"id":"d","text":"A context filter set to display only records where Sales exceeds the grand average"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A FIXED [Region] : AVG([Order Total]) LOD expression computes the average order total for each region independently of the view granularity. This regional average can then be compared to each individual order (at row-level granularity) in a calculated field like [Order Total] > { FIXED [Region] : AVG([Order Total]) }. WINDOW_AVG operates on visible table partitions and is view-dependent. EXCLUDE LOD removes dimensions from aggregation rather than anchoring to a dimension, making it less appropriate here. A context filter on grand average doesn't perform region-specific comparisons.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau Help – Level of Detail Expressions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to find customers whose individual order total is above the average order total for their respective region. Which Tableau expression type is best suited for this analysis?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst adds the Forecast feature from the Analytics pane to a time-series line chart. The forecast appears grayed out with no projection. What is the most likely reason?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The analyst does not have Tableau Creator license required for forecasting"},{"id":"b","text":"There is insufficient historical data — Tableau requires at least five data points to generate a forecast"},{"id":"c","text":"Forecasting is only available when connected to a Tableau Extract, not a live connection"},{"id":"d","text":"The date field must be placed on the Columns shelf at the Day level of detail for forecasting to work"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau's forecasting engine uses exponential smoothing algorithms and requires a minimum number of historical data points to generate a reliable forecast. If fewer than five data points (or in some seasonal models, fewer seasons worth of data) are available, Tableau cannot produce the forecast and it appears greyed out. Forecasting is available to all Tableau Desktop users regardless of license tier (Creator, Explorer). Forecasting works on both live connections and extracts. The date field can be at various time levels (Month, Quarter, etc.); it does not need to be at Day level.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/forecast_how_it_works.htm","label":"Tableau Help – How Forecasting Works in Tableau"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst adds the Forecast feature from the Analytics pane to a time-series line chart. The forecast appears grayed out with no projection. What is the most likely reason?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst is exploring customer segmentation and drags a cluster model from the Analytics pane onto a scatter plot showing Customer Lifetime Value vs. Purchase Frequency. What algorithm does Tableau use internally for this clustering?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Hierarchical agglomerative clustering"},{"id":"b","text":"DBSCAN (Density-Based Spatial Clustering of Applications with Noise)"},{"id":"c","text":"K-means clustering"},{"id":"d","text":"Gaussian Mixture Model (GMM) clustering"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau's built-in clustering feature (accessible via the Analytics pane) uses the k-means algorithm. K-means partitions data into k clusters by minimizing the within-cluster sum of squared distances to the cluster centroid. Tableau automatically suggests a number of clusters but allows the analyst to override it. Hierarchical, DBSCAN, and GMM clustering methods are not natively implemented in Tableau's clustering feature, though they can be accessed via Tableau's external services integration (TabPy, R).$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/clusteranalysis.htm","label":"Tableau Help – Cluster Analysis in Tableau"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst is exploring customer segmentation and drags a cluster model from the Analytics pane onto a scatter plot showing Customer Lifetime Value vs. Purchase Frequency. What algorithm does Tableau use internally for this clustering?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Tableau feature would an analyst use to answer the question: 'For each customer, how many days elapsed between their first and most recent purchase?'$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A FIXED LOD expression using DATEDIFF with MIN(Order Date) and MAX(Order Date) anchored to Customer"},{"id":"b","text":"A WINDOW_MAX table calculation subtracted from WINDOW_MIN on the Order Date dimension"},{"id":"c","text":"A RUNNING_SUM of Order Date values to accumulate date differences"},{"id":"d","text":"A date filter scoped to the first and last calendar dates in the dataset"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$DATEDIFF('day', {FIXED [Customer ID] : MIN([Order Date])}, {FIXED [Customer ID] : MAX([Order Date])}) computes the number of days between the earliest and latest order for each customer, independently of the view granularity. This is a classic FIXED LOD use case for cohort and customer tenure analysis. WINDOW_MAX/MIN are table calculations that depend on the view structure and partitioning, making them fragile for this use case. RUNNING_SUM of date values has no meaningful interpretation. A date filter restricts the dataset rather than computing elapsed time.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_date.htm","label":"Tableau Help – DATEDIFF Function"},{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau Help – Level of Detail Expressions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Tableau feature would an analyst use to answer the question: 'For each customer, how many days elapsed between their first and most recent purchase?'$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is reviewing a box-and-whisker plot in Tableau showing distribution of order values. One mark appears far to the right of the upper whisker. What does this mark represent?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A data point within the interquartile range (IQR)"},{"id":"b","text":"An outlier that falls beyond 1.5 times the IQR from the upper quartile"},{"id":"c","text":"The maximum value within the dataset, always plotted separately from the box"},{"id":"d","text":"A reference line indicating the 95th percentile of order values"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$In Tableau's box-and-whisker plot, the whiskers extend to the furthest data point within 1.5 × IQR from the first and third quartiles (Tukey's method). Any data point beyond the whisker boundary is plotted as an individual mark and classified as an outlier. It does not represent the absolute maximum (the maximum may lie within the whisker range). It is not within the IQR, and it is not a reference line — it is an actual data point mark.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/buildexamples_boxplot.htm","label":"Tableau Help – Box Plots"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is reviewing a box-and-whisker plot in Tableau showing distribution of order values. One mark appears far to the right of the upper whisker. What does this mark represent?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is building a sales dashboard and wants viewers to be able to click on a region mark to dynamically filter all other worksheets on the dashboard to that region. Which Tableau feature provides this capability?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A URL action configured to pass the region value as a parameter"},{"id":"b","text":"A Filter action that uses the source sheet's selection as the filter for target sheets"},{"id":"c","text":"A parameter action that updates a region parameter when a mark is clicked"},{"id":"d","text":"A Highlight action that emphasizes related marks across sheets"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Filter action in Tableau Dashboard actions allows a user's mark selection on a source sheet to act as a filter on one or more target sheets. When a region is clicked, the action passes the selected dimension value as a filter to the specified target worksheets, making this the standard way to implement cross-sheet filtering interactivity. A URL action navigates to a web page. A parameter action updates a parameter value, which can be used for filtering but requires an additional calculated field tied to the parameter. A Highlight action visually emphasizes related marks but does not filter out unrelated data.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/actions_filter.htm","label":"Tableau Help – Dashboard Actions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is building a sales dashboard and wants viewers to be able to click on a region mark to dynamically filter all other worksheets on the dashboard to that region. Which Tableau feature provides this capability?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to display sales data on a map view and needs to distinguish between areas of high and low density using color gradients. The data contains latitude/longitude coordinates. Which mark type is most appropriate for this in Tableau?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Symbol map using circle marks colored by Sum(Sales)"},{"id":"b","text":"Density map (heatmap) using the Density mark type with latitude and longitude"},{"id":"c","text":"Filled map using polygon marks for each latitude/longitude point"},{"id":"d","text":"A pie chart map using latitude/longitude as the geographic anchor"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau's Density mark type (available in the Marks card drop-down) renders a geographic heatmap that uses color gradients to visualize the concentration of data points across a map. It is specifically designed for showing density distributions where many overlapping points create visual patterns. A Symbol map uses individual circle marks per point, which works for discrete comparison but not density gradients. Filled maps shade geographic regions (countries, states) using built-in boundaries, not arbitrary lat/lon density. Pie chart maps show composition per location, not spatial density.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/maps_howto_density.htm","label":"Tableau Help – Density Maps"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to display sales data on a map view and needs to distinguish between areas of high and low density using color gradients. The data contains latitude/longitude coordinates. Which mark type is most appropriate for this in Tableau?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst uses the EXCLUDE LOD expression { EXCLUDE [Sub-Category] : SUM([Sales]) }. When this field is placed in a view that already contains [Category] and [Sub-Category], what does the expression compute?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The sum of sales for each unique Sub-Category, independent of Category"},{"id":"b","text":"The sum of sales aggregated at the Category level only, excluding Sub-Category from the aggregation"},{"id":"c","text":"The grand total of all sales across the entire dataset"},{"id":"d","text":"The sum of sales at the most granular level of the view, excluding NULL Sub-Category values"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$An EXCLUDE LOD expression removes the specified dimension(s) from the view's level of detail for that calculation. In a view containing [Category] and [Sub-Category], EXCLUDE [Sub-Category] causes the SUM([Sales]) to be computed at the [Category] level only — effectively giving the category total regardless of which sub-category row is being displayed. This is useful for computing ratios like 'sub-category sales as % of category total.' Option A describes a FIXED [Sub-Category] expression. Option C would be a FIXED LOD with no dimensions. Option D is incorrect regarding NULL filtering.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau Help – Level of Detail Expressions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst uses the EXCLUDE LOD expression { EXCLUDE [Sub-Category] : SUM([Sales]) }. When this field is placed in a view that already contains [Category] and [Sub-Category], what does the expression compute?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst has a calculated field with the expression: IF INDEX() = 1 THEN 'First' ELSE 'Other' END. What type of calculation is this, and why?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A row-level calculation, because INDEX() operates on individual database rows"},{"id":"b","text":"A table calculation, because INDEX() returns the row number within the current partition of the view and is computed post-aggregation"},{"id":"c","text":"An LOD expression, because it references the first record in a fixed dimension group"},{"id":"d","text":"An aggregate calculation, because IF logic always implies aggregation in Tableau"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$INDEX() is a Tableau table calculation function that returns the sequential row number (index) of the current row within the current partition of the view, evaluated after aggregation and rendering. This makes any calculated field using INDEX() a table calculation. Table calculations are computed on the Tableau client after data is retrieved from the source, not at the database level. INDEX() is not a row-level function (those access unaggregated fields directly). It is not an LOD expression. IF logic alone does not determine aggregation type.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_tablecalculation.htm","label":"Tableau Help – Table Calculation Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst has a calculated field with the expression: IF INDEX() = 1 THEN 'First' ELSE 'Other' END. What type of calculation is this, and why?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which of the following best describes the purpose of using a 'Explain Data' (Explain the Data) feature in Tableau Desktop?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It generates an automated data quality report listing missing values and duplicates in the dataset"},{"id":"b","text":"It uses statistical analysis to surface potential explanations for unexpected values or outliers in a selected mark"},{"id":"c","text":"It documents the data lineage and source metadata for compliance auditing purposes"},{"id":"d","text":"It exports a written summary of all calculated fields and their formulas in the workbook"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Explain Data (also called 'Explain the Data') in Tableau Desktop applies automated statistical analysis to a selected mark in a visualization. It investigates contributing factors from other fields in the data source and surfaces possible explanations for why a particular value is anomalous or notable — such as an unexpected spike or drop. It is not a data quality audit tool, a lineage tracker, or a formula documentation exporter. It focuses specifically on contextual statistical explanations for observed values.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/explain_data.htm","label":"Tableau Help – Explain Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which of the following best describes the purpose of using a 'Explain Data' (Explain the Data) feature in Tableau Desktop?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst needs to display sales data so that the mark color transitions smoothly from blue for the lowest values to red for the highest values. Which color palette type should the analyst select in the Edit Colors dialog?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Categorical palette"},{"id":"b","text":"Sequential palette"},{"id":"c","text":"Diverging palette"},{"id":"d","text":"Custom discrete palette"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Sequential palette transitions smoothly from one color to another across a continuous range of values, making it ideal for showing magnitude from low to high (e.g., blue to red). A Categorical palette assigns distinct colors to discrete members. A Diverging palette uses two contrasting colors that meet at a meaningful midpoint, which is not described here. A Custom discrete palette applies fixed colors to specific values rather than a smooth gradient.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/formatting_create_custom_colors.htm","label":"Tableau – Color Palettes and Effects"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
