  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst needs to display sales data so that the mark color transitions smoothly from blue for the lowest values to red for the highest values. Which color palette type should the analyst select in the Edit Colors dialog?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to build a view that simultaneously shows individual order profit values as bars AND a running-total line on the same axis. Which Tableau feature allows both mark types to coexist on a single pane sharing the same axis?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Dual-axis chart"},{"id":"b","text":"Combined axis chart"},{"id":"c","text":"Blended axis chart"},{"id":"d","text":"Combination chart using Marks card layers"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$A combination chart (also called a combo chart) in Tableau uses individual mark-type layers on the Marks card to display different mark types — such as Bar and Line — on the same axis within the same pane. A dual-axis chart creates two separate, synchronized axes. A 'blended axis' is not a standard Tableau feature name. 'Combined axis' refers to dragging multiple measures onto the same axis, which does not inherently provide separate mark-type control per measure.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/qs_combo_charts.htm","label":"Tableau – Build a Combination Chart"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
