INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is designing a dashboard and wants a text object that always displays the current workbook name and the date the dashboard was last refreshed. Which Tableau feature enables dynamic, auto-updating text of this kind?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A floating text object with a hard-coded string"},{"id":"b","text":"A title with automatic formatting only"},{"id":"c","text":"Inserting dynamic values such as <Workbook Name> and <Last Refresh Date> into a text or title object"},{"id":"d","text":"A sheet with a custom calculated field referencing TODAY()"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau supports dynamic insert tokens (e.g., <Workbook Name>, <Last Refresh Date>, <User Name>, <Page Name>) that can be inserted into text objects, titles, and captions. These tokens update automatically. Hard-coded strings never update. A title with only automatic formatting does not insert workbook metadata. Using TODAY() in a calculated field gives a date but cannot reference workbook metadata like the workbook name.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/formatting_workbook_title.htm","label":"Tableau – Add Dynamic Text to Titles and Tooltips"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is designing a dashboard and wants a text object that always displays the current workbook name and the date the dashboard was last refreshed. Which Tableau feature enables dynamic, auto-updating text of this kind?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to create a view where clicking a mark on a regional sales bar chart filters a separate profit scatter plot on the same dashboard — but ONLY affects that scatter plot and no other sheets. Which dashboard action type and scope setting achieves this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A Highlight action targeted at all sheets using 'Hover' as the trigger"},{"id":"b","text":"A Filter action with the source set to the bar chart and the target set specifically to the scatter plot, triggered by 'Select'"},{"id":"c","text":"A URL action assigned to the bar chart that redirects to the scatter plot view"},{"id":"d","text":"A Parameter action that updates a parameter consumed by a calculated field in all sheets"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Filter action allows precise configuration of source sheet, target sheet(s), and trigger type. By setting the source to the regional bar chart and the target exclusively to the scatter plot, only the scatter plot responds to selections. A Highlight action does not filter data — it dims non-matching marks across all sheets. A URL action navigates to a URL, not a cross-sheet filter. A Parameter action updates a shared parameter which would affect every sheet that references it.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/actions_filter.htm","label":"Tableau – Filter Actions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst needs to create a view where clicking a mark on a regional sales bar chart filters a separate profit scatter plot on the same dashboard — but ONLY affects that scatter plot and no other sheets. Which dashboard action type and scope setting achieves this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst wants to show year-over-year profit change in a view using a quick table calculation. After placing Profit on Rows, which Quick Table Calculation option should the analyst choose to display how each year's profit differs from the prior year's value?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Running Total"},{"id":"b","text":"Moving Average"},{"id":"c","text":"Difference"},{"id":"d","text":"Percent of Total"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$The 'Difference' quick table calculation subtracts each value from the prior value along the specified addressing direction (e.g., across years), which directly expresses year-over-year change. 'Running Total' accumulates values, not differences. 'Moving Average' smooths data over a window of periods rather than computing a single-step difference. 'Percent of Total' expresses each value as a share of a grand total.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_tablecalculations_quick.htm","label":"Tableau – Quick Table Calculations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst wants to show year-over-year profit change in a view using a quick table calculation. After placing Profit on Rows, which Quick Table Calculation option should the analyst choose to display how each year's profit differs from the prior year's value?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is building a Tableau story and wants viewers to step through three analytical insights in a guided sequence. Which Story Point configuration should the analyst use to present a new caption and a distinct dashboard layout for each insight?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Add three separate worksheets inside a single story point and toggle between them using sheet tabs"},{"id":"b","text":"Create one story point per insight, give each a descriptive caption, and assign each the relevant dashboard or sheet as its content"},{"id":"c","text":"Use three floating containers on a single dashboard to simulate story-point navigation"},{"id":"d","text":"Publish three separate workbooks and link them via URL actions"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau Stories are built from individual Story Points, each of which has its own caption and displays one sheet or dashboard. Creating one story point per insight with a unique caption and dedicated content is the standard, supported approach for guided narratives. Sheet tabs inside a story point do not provide separate story-point captions. Floating containers on a single dashboard are a layout technique, not a story feature. Publishing separate workbooks adds unnecessary complexity and breaks the unified story experience.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/story_create.htm","label":"Tableau – Create a Story"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is building a Tableau story and wants viewers to step through three analytical insights in a guided sequence. Which Story Point configuration should the analyst use to present a new caption and a distinct dashboard layout for each insight?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A dashboard has a tiled layout. The analyst wants to add a company logo image that always stays in the top-right corner regardless of how the dashboard is resized. Which container type should be used for the image object?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Tiled object placed in an outer horizontal container"},{"id":"b","text":"Floating object anchored to the top-right with fixed coordinates"},{"id":"c","text":"Tiled object inside a vertical container aligned to the bottom"},{"id":"d","text":"A blank padding object next to the image in the tiled grid"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Floating objects in Tableau dashboards are positioned using fixed pixel coordinates and do not reflow with the tiled layout. Anchoring a floating image to the top-right corner ensures it remains in that position regardless of dashboard size changes. Tiled objects reflow within containers when the dashboard is resized. A vertical container aligned to the bottom moves the object down, not to the top-right. Padding objects do not fix position.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/dashboards_organize_floatingandtiled.htm","label":"Tableau – Dashboard Layout and Formatting"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A dashboard has a tiled layout. The analyst wants to add a company logo image that always stays in the top-right corner regardless of how the dashboard is resized. Which container type should be used for the image object?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is creating a bar chart that ranks products by revenue. The analyst wants the bars sorted so the highest-revenue product always appears at the top, even after new data is loaded. Which sort method ensures this dynamic, data-driven ordering?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Manual sort — drag product names into the desired order in the header"},{"id":"b","text":"Alphabetical sort on the product name dimension"},{"id":"c","text":"Sort by Field — sort the dimension by the SUM(Revenue) measure in descending order"},{"id":"d","text":"Sort by Data Source Order to preserve the ETL sequence"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Sorting a dimension by a measure field (Sort by Field) instructs Tableau to re-rank the dimension members each time the view is rendered, based on the current aggregated value of the measure. This is dynamic and updates automatically with new data. Manual sort assigns a fixed position, which breaks when new data introduces different values. Alphabetical sort orders members lexicographically, not by revenue. Data Source Order reflects the physical row order in the underlying data, which has no meaningful revenue-ranking logic.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/sortgroup_sorting_computed_howto.htm","label":"Tableau – Sort Data in a Visualization"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is creating a bar chart that ranks products by revenue. The analyst wants the bars sorted so the highest-revenue product always appears at the top, even after new data is loaded. Which sort method ensures this dynamic, data-driven ordering?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to display grand totals at the bottom of a crosstab view in Tableau. After navigating to the Analysis menu, which option and sub-selection correctly adds a grand total row for all columns?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Analysis > Totals > Show Column Grand Totals"},{"id":"b","text":"Analysis > Totals > Show Row Grand Totals"},{"id":"c","text":"Analysis > Aggregate Measures > Sum"},{"id":"d","text":"Analysis > Create Calculated Field using TOTAL()"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$In Tableau, 'Row Grand Totals' adds a totals row at the bottom of the view — it aggregates across all columns for each row measure. 'Column Grand Totals' adds a totals column on the right side of the view, aggregating across rows. 'Aggregate Measures' controls whether measures are aggregated in the view, not where totals appear. A TOTAL() calculated field can compute running totals in table calculations but is not the way to add the built-in grand totals footer row.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_totals_grandtotals_add.htm","label":"Tableau – Show Totals in a Visualization"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to display grand totals at the bottom of a crosstab view in Tableau. After navigating to the Analysis menu, which option and sub-selection correctly adds a grand total row for all columns?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst has a scatter plot with hundreds of overlapping marks. They want to visually communicate the density of overlapping points without changing the chart type. Which Tableau formatting option BEST addresses mark overlap in this scenario?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Increase the mark size to make individual points more visible"},{"id":"b","text":"Reduce mark opacity on the Marks card so overlapping marks appear darker where concentrated"},{"id":"c","text":"Enable 'Stack Marks' to layer the points vertically"},{"id":"d","text":"Switch the mark type from Circle to Square"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Reducing mark opacity (transparency) causes overlapping marks to compound visually — areas with many stacked marks appear more saturated/darker, intuitively communicating density. This is a standard technique for overplotting. Increasing mark size worsens overlap. 'Stack Marks' is relevant to bar charts, not scatter plots. Changing mark shape from Circle to Square does not address density communication.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/viewparts_marks_markproperties.htm","label":"Tableau – Change the Appearance of Marks in the View"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst has a scatter plot with hundreds of overlapping marks. They want to visually communicate the density of overlapping points without changing the chart type. Which Tableau formatting option BEST addresses mark overlap in this scenario?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst needs to add a reference line to a view that dynamically shows the average sales across all marks currently displayed in the view, updating automatically as filters change. Which reference line Value setting achieves this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A constant value reference line set to the known historical average"},{"id":"b","text":"A reference line with Value set to a fixed parameter that the user adjusts manually"},{"id":"c","text":"A reference line with Value set to Average of SUM(Sales) scoped to the entire table"},{"id":"d","text":"A reference band between minimum and maximum values"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$When adding a reference line via the Analytics pane, setting the Value to an aggregation (such as Average) of a measure scoped to 'Table' causes Tableau to recalculate the line each time the view updates, including after filters are applied. A constant value never changes with the data. A parameter-based line only changes when the user manually adjusts the parameter, not automatically with filters. A reference band marks a range, not a single average line.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/reference_lines.htm","label":"Tableau – Add Reference Lines, Bands, Distributions, and Box Plots"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst needs to add a reference line to a view that dynamically shows the average sales across all marks currently displayed in the view, updating automatically as filters change. Which reference line Value setting achieves this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When using the Tableau tooltip editor, an analyst wants to show a small fully interactive embedded chart inside the tooltip that appears when a user hovers over a mark. Which Tableau feature enables this capability?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Tooltip text formatting with bold and italic markup"},{"id":"b","text":"Viz in Tooltip — inserting a reference to another sheet inside the tooltip editor"},{"id":"c","text":"Embedding a URL action that opens an image in the tooltip"},{"id":"d","text":"Adding a dashboard action that swaps the current sheet on hover"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Viz in Tooltip is a Tableau feature that allows analysts to embed a live, interactive mini-visualization from another sheet directly inside a tooltip. The embedded viz filters automatically based on the hovered mark. Tooltip text formatting is purely cosmetic. URL actions open external URLs and do not embed charts. Dashboard sheet-swap actions replace an entire sheet container, which is not the same as an inline tooltip visualization.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/viz_in_tooltip.htm","label":"Tableau – Create Views That Appear in Tooltips (Viz in Tooltip)"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$When using the Tableau tooltip editor, an analyst wants to show a small fully interactive embedded chart inside the tooltip that appears when a user hovers over a mark. Which Tableau feature enables this capability?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau Desktop author has finished building a workbook and wants to publish it to Tableau Server so that other users in the Sales group can access it. Which permission capability must be granted to the Sales group on the project to allow members to VIEW the published workbook?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Download/Save a Copy"},{"id":"b","text":"View"},{"id":"c","text":"Web Edit"},{"id":"d","text":"Overwrite"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The 'View' permission capability is the fundamental capability that allows users to see published content on Tableau Server or Tableau Cloud. Without 'View', users cannot access the workbook at all. 'Download/Save a Copy' allows downloading the workbook locally, 'Web Edit' allows editing in the browser, and 'Overwrite' allows replacing the existing published workbook — none of these grant the basic ability to view the content.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/server/en-us/permissions.htm","label":"Tableau Help – Permissions"},{"url":"https://help.tableau.com/current/server/en-us/permissions_capabilities.htm","label":"Tableau Help – Permission Capabilities"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau Desktop author has finished building a workbook and wants to publish it to Tableau Server so that other users in the Sales group can access it. Which permission capability must be granted to the Sales group on the project to allow members to VIEW the published workbook?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When publishing a workbook to Tableau Server, an author wants to ensure that the embedded database credentials are stored securely and used automatically when viewers open the workbook. Which option should the author select in the Publish dialog box to achieve this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Prompt users for credentials each time they open the workbook"},{"id":"b","text":"Allow refresh access"},{"id":"c","text":"Embed password in the published workbook"},{"id":"d","text":"Use a Tableau extract instead of a live connection"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Selecting 'Embed password in the published workbook' stores the data source credentials securely within the published content on Tableau Server, allowing viewers to access the workbook without being prompted for credentials. 'Prompt users' requires each viewer to supply their own credentials. 'Allow refresh access' is specific to extract refresh scheduling, not viewer authentication. Switching to an extract does not address how credentials are stored or used when the connection is live.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/publishing_sharing_authentication.htm","label":"Tableau Help – Set Credentials for Accessing Your Published Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$When publishing a workbook to Tableau Server, an author wants to ensure that the embedded database credentials are stored securely and used automatically when viewers open the workbook. Which option should the author select in the Publish dialog box to achieve this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data analyst publishes a workbook to a Tableau Server project that has the permission model set to 'Locked'. What is the effect of the locked permission model on workbook-level permissions?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Workbook-level permissions override the project-level permissions for all users."},{"id":"b","text":"Workbook-level permissions are disabled; only project-level permissions apply to all content in the project."},{"id":"c","text":"Workbook-level permissions can still be customized by the workbook owner only."},{"id":"d","text":"The locked model applies only to data sources, not to workbooks."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$When a project's permission model is set to 'Locked', all content within that project inherits the project-level permissions and individual content-level (workbook-level) permissions cannot be customized. This provides consistent, centrally managed access control. The locked model applies to all content types in the project, including workbooks and data sources. A 'Customizable' project model, by contrast, allows content owners to set permissions at the workbook or data source level.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/server/en-us/permissions_projects.htm#lock-content-permissions","label":"Tableau Help – Lock Content Permissions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A data analyst publishes a workbook to a Tableau Server project that has the permission model set to 'Locked'. What is the effect of the locked permission model on workbook-level permissions?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to schedule an extract refresh for a published data source on Tableau Server so the data is updated every morning at 6 AM. Where in the Tableau Server web interface should the analyst configure this schedule?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Navigate to the data source on Tableau Server and select 'Refresh Extracts' from the data source actions menu."},{"id":"b","text":"Edit the workbook in Tableau Desktop and use the Data menu to schedule the refresh."},{"id":"c","text":"Go to the Server Admin area and modify the background task runner configuration."},{"id":"d","text":"Open the data source in Tableau Prep Builder and configure the output schedule."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$After a data source containing an extract is published to Tableau Server, owners and Server Administrators can schedule extract refreshes directly from the data source's actions menu on the Tableau Server web interface by selecting 'Refresh Extracts' and choosing or creating a refresh schedule. Scheduling is not done through Tableau Desktop's Data menu, the background task runner admin settings, or Tableau Prep Builder's output options.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/server/en-us/schedule_add.htm","label":"Tableau Help – Refresh Data on a Schedule"},{"url":"https://help.tableau.com/current/server/en-us/schedule_manage_extract.htm","label":"Tableau Help – Extract Refresh Schedules"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to schedule an extract refresh for a published data source on Tableau Server so the data is updated every morning at 6 AM. Where in the Tableau Server web interface should the analyst configure this schedule?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau Server administrator wants to organize published content so that the Finance and Marketing departments each have their own isolated workspace with separate permission sets. Which Tableau Server organizational structure should the administrator use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Create separate workbooks for each department within a single shared project."},{"id":"b","text":"Create top-level projects for Finance and Marketing, applying distinct permission sets to each project."},{"id":"c","text":"Create separate Tableau Server sites for Finance and Marketing."},{"id":"d","text":"Use workbook-level tags to filter content by department."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Projects are the primary organizational unit in Tableau Server for grouping related content and applying consistent permission sets. Creating top-level projects for Finance and Marketing and assigning distinct group-based permissions to each project provides isolated workspaces with appropriate access control. Separate sites offer complete isolation but are typically reserved for truly distinct organizations or environments, not just departmental separation. Workbooks within a single project share the project's permissions, and tags are for discoverability rather than access control.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/server/en-us/projects.htm","label":"Tableau Help – Use Projects to Manage Content Access"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P2'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau Server administrator wants to organize published content so that the Finance and Marketing departments each have their own isolated workspace with separate permission sets. Which Tableau Server organizational structure should the administrator use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst publishes a workbook to Tableau Cloud and wants to share a specific dashboard view with a stakeholder who does not have a Tableau account. Which Tableau feature allows the analyst to share the view publicly without requiring the stakeholder to log in?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Download the view as a PDF and email it to the stakeholder."},{"id":"b","text":"Enable 'Ask Data' on the published workbook and share the link."},{"id":"c","text":"Use Tableau Public to publish the workbook and share the public URL."},{"id":"d","text":"Grant the stakeholder a Guest user license on Tableau Cloud."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau Public is a free platform where workbooks can be published and viewed by anyone without requiring a Tableau account or login. This is the appropriate solution for sharing content publicly with stakeholders who do not have Tableau credentials. Downloading as a PDF is a workaround, not a Tableau sharing feature, and does not provide interactivity. 'Ask Data' still requires Tableau Cloud authentication. Guest user licenses exist on Tableau Server but not on Tableau Cloud, and they still require a login.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://public.tableau.com/en-us/s/about","label":"Tableau Public – About Tableau Public"},{"url":"https://help.tableau.com/current/pro/desktop/en-us/publish_workbooks_tableaupublic.htm","label":"Tableau Help – Publish to Tableau Public"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
