INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst needs to compare sales across four product categories over a three-year period while also showing the proportion each category contributes to the total for each year. Which chart type is MOST appropriate for this combined requirement?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Stacked bar chart"},{"id":"b","text":"Side-by-side bar chart"},{"id":"c","text":"Line chart with dual axis"},{"id":"d","text":"Scatter plot with color encoding"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$A stacked bar chart lets viewers compare the total magnitude across years (the full bar height) while simultaneously showing each category's proportional contribution within each year (the individual segments). A side-by-side bar makes comparison across categories easy but loses the proportional context. A dual-axis line chart is better for two measures over time. A scatter plot is suited for correlation analysis, not part-to-whole over time.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/what_chart_is_right.htm","label":"Tableau – Choose the Right Chart Type"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
