INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst creates a calculated field using the expression `FIXED [Region] : SUM([Sales])`. When this field is placed on a view that also contains [Category] in the level of detail, what does the FIXED LOD expression return for each mark?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The SUM of Sales for each unique Region, regardless of any other dimensions in the view"},{"id":"b","text":"The SUM of Sales for each Region–Category combination"},{"id":"c","text":"The SUM of Sales across the entire dataset, ignoring all dimensions"},{"id":"d","text":"The SUM of Sales filtered by the current context filter for Region"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$FIXED LOD expressions compute the aggregate at the specified dimension level regardless of what other dimensions are present in the view. So `{FIXED [Region] : SUM([Sales])}` always returns the total Sales for the Region dimension alone, even if [Category] is also on the view. EXCLUDE removes dimensions from the view's level of detail, and INCLUDE adds dimensions. FIXED is not affected by dimension filters (only context filters and data source filters override it).$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau – Level of Detail Expressions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
