INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst writes the table calculation `WINDOW_AVG(SUM([Sales]))` and the compute-using setting is set to 'Table (across)'. What does this calculation return for each mark in the view?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The average of SUM(Sales) across all columns in the current row of the table"},{"id":"b","text":"The running total of SUM(Sales) from left to right"},{"id":"c","text":"The average of SUM(Sales) computed independently for each individual mark"},{"id":"d","text":"The percentage of total SUM(Sales) relative to the grand total"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$WINDOW_AVG computes the average of its expression over a window (partition). When compute-using is 'Table (across)', the window spans all columns in the same row, so every mark in a row receives the same value: the average of SUM(Sales) across all columns in that row. A running total uses RUNNING_SUM. Per-mark computation would simply be SUM(Sales) itself. Percentage of total uses a different table calculation.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_tablecalculations_definebasic_windowavg.htm","label":"Tableau – Table Calculations Reference"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
