INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A calculated field contains the expression `DATEDIFF('month', [Order Date], TODAY())`. What does this expression return?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The number of complete months between the Order Date and the current date"},{"id":"b","text":"The date exactly one month before the Order Date"},{"id":"c","text":"A formatted string showing the month difference"},{"id":"d","text":"The number of days between the Order Date and the current date divided by 30"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$DATEDIFF(date_part, start_date, end_date) returns an integer representing the number of date_part intervals between start_date and end_date. With 'month' as the date_part, it counts the number of month boundaries crossed, not a decimal fraction. TODAY() returns the current date. The result is an integer, not a formatted string, and it is not calculated by dividing days by 30.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_date.htm","label":"Tableau – DATEDIFF Function"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
