INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When publishing a workbook to Tableau Server or Tableau Cloud, an analyst selects the option 'Publish Tabs as Sheets'. What is the primary effect of enabling this option?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Each worksheet tab in the workbook becomes an individually addressable view that can be managed and permissioned separately."},{"id":"b","text":"The workbook is split into multiple separate workbook files, one per sheet."},{"id":"c","text":"All worksheets are merged into a single dashboard that users can scroll through."},{"id":"d","text":"The workbook is automatically embedded into a SharePoint site with individual tab links."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Selecting 'Show Sheets as Tabs' (Publish Tabs) during publish makes each individual sheet visible as a separate named view on Tableau Server/Cloud. Users can bookmark or share direct links to individual sheets. The workbook remains a single file — it is not split into multiple workbooks (option b). Sheets are not merged into a scrollable dashboard (option c). SharePoint embedding is a separate integration and is not triggered by this option (option d).$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/publish_workbooks_howto.htm","label":"Tableau Help – Publish a Workbook"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
