INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data analyst needs to publish a workbook to Tableau Server and ensure that the embedded data source credentials are stored securely on the server so that scheduled extracts can refresh without prompting end users. Which credential option should the analyst choose during the publish workflow?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Prompt users for credentials at runtime"},{"id":"b","text":"Embed credentials in the published data source"},{"id":"c","text":"Use a Tableau Bridge connection"},{"id":"d","text":"Set the data source to public so no credentials are needed"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Embedding credentials in the published data source stores the database username and password securely on Tableau Server, enabling automated extract refreshes without user interaction. Prompting users at runtime (option a) is suitable for interactive sessions but breaks unattended scheduled refreshes. Tableau Bridge (option c) is used for reaching on-premises data from Tableau Cloud, not specifically for credential storage. Making a data source public (option d) does not apply to database credential requirements and creates a security risk.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/publishing_sharing_authentication.htm","label":"Tableau Help – Set Credentials for Accessing Your Published Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
