         $json$[{"id":"a","text":"Revision History"},{"id":"b","text":"Subscriptions"},{"id":"c","text":"Extract Refresh Schedule"},{"id":"d","text":"Data-Driven Alert"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$An Extract Refresh Schedule allows Tableau Server to automatically re-query the underlying data source and rebuild the extract at a defined interval (e.g., nightly). Revision History (option a) tracks saved versions of published content but does not refresh data. Subscriptions (option b) email snapshots of views to users on a schedule but do not update the extract data. Data-Driven Alerts (option d) notify users when a metric crosses a threshold but do not trigger extract updates.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/server/en-us/schedules_add.htm","label":"Tableau Help – Refresh Extracts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
