INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau Server site administrator enables 'Lock Project Permissions' on a project. What is the direct consequence of this setting?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Users can no longer publish new content to that project."},{"id":"b","text":"Permission rules set at the project level override and replace any content-level permission customizations within that project."},{"id":"c","text":"The project and all its content become read-only for all users, including administrators."},{"id":"d","text":"Content in the project is automatically exported to a backup file when permissions change."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$When a project's permissions are locked, Tableau Server enforces the project-level permission template on all content within that project. Any per-content permission customizations are overridden, ensuring consistent access control. Users with Publish capability can still publish new content (option a is incorrect). Administrators retain their rights and content is not globally read-only (option c is incorrect). No backup export is triggered by locking permissions (option d is incorrect).$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/server/en-us/permissions_projects.htm","label":"Tableau Help – Lock Content Permissions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
