  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau Desktop analyst connects to a large SQL Server database containing millions of rows. After noticing slow dashboard performance, the analyst wants to store a snapshot of the data locally for faster querying. Which connection type should the analyst configure?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is building a data source in Tableau Desktop and needs to combine a 'Sales' table with a 'Returns' table. Only rows from the 'Sales' table that have a matching record in the 'Returns' table should appear in the result. Which join type should the analyst use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Left join"},{"id":"b","text":"Right join"},{"id":"c","text":"Inner join"},{"id":"d","text":"Full outer join"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$An Inner join returns only the rows where there is a matching value in both tables, which is exactly what is needed here. A Left join returns all rows from the left table and matched rows from the right. A Right join returns all rows from the right table and matched rows from the left. A Full outer join returns all rows from both tables regardless of matches.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/joining_tables.htm","label":"Tableau - Join Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
