INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to combine data from two separate Excel files that have identical column structures — one containing Q1 sales and another containing Q2 sales. The analyst needs all rows from both files in a single data source without duplicating columns. Which Tableau feature best accomplishes this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Join"},{"id":"b","text":"Blend"},{"id":"c","text":"Union"},{"id":"d","text":"Cross-database join"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A Union stacks rows from tables with the same column structure, making it ideal for appending Q1 and Q2 data. A Join combines tables horizontally by matching on a key column. A Blend combines data from separate data sources at the view level and does not create a single merged dataset. A Cross-database join joins tables from different database types but still combines data horizontally, not vertically.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/union.htm","label":"Tableau - Union Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to combine data from two separate Excel files that have identical column structures — one containing Q1 sales and another containing Q2 sales. The analyst needs all rows from both files in a single data source without duplicating columns. Which Tableau feature best accomplishes this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau Desktop, which of the following best describes the purpose of a 'Data Source Filter'?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It filters data after aggregation has been applied in the view."},{"id":"b","text":"It restricts the rows of data retrieved from the source before any analysis is performed."},{"id":"c","text":"It applies a filter only to a specific worksheet within a workbook."},{"id":"d","text":"It prevents users from modifying dimensions in the data pane."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Data Source Filter is applied at the data source level and limits the rows fetched from the underlying data before any calculations or visualizations are built. This makes it the earliest point in the Tableau order of operations for filtering. It is not applied after aggregation (that would be a HAVING-equivalent or table calculation filter), nor is it scoped to a single worksheet. It has no effect on preventing modifications to the data pane.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/filtering_datasource.htm","label":"Tableau - Filter Data from Data Sources"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau Desktop, which of the following best describes the purpose of a 'Data Source Filter'?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst connects to a flat CSV file and notices that Tableau has incorrectly interpreted a 'Postal Code' column as a Number data type. What is the most direct way to correct this in the Data Source pane?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Create a calculated field that casts the column using STR()."},{"id":"b","text":"Click the data type icon above the column header in the Data Source pane and select String."},{"id":"c","text":"Right-click the field in the Data pane and select 'Convert to Dimension'."},{"id":"d","text":"Use a data source filter to exclude numeric values."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$In the Data Source pane, each column has a data type icon (Abc, #, calendar, etc.) that can be clicked to change the data type directly. Changing 'Postal Code' from Number to String prevents Tableau from treating it as a measure or performing invalid numeric aggregations. Creating a calculated field with STR() is a workaround but is not the most direct method. Converting to a Dimension changes the role but not the underlying data type. A data source filter does not change data types.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/datafields_typesandroles_datatypes.htm","label":"Tableau - Tableau Data Types"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst connects to a flat CSV file and notices that Tableau has incorrectly interpreted a 'Postal Code' column as a Number data type. What is the most direct way to correct this in the Data Source pane?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau extract is scheduled to refresh every night on Tableau Server, but the underlying source database credentials have changed. Where in Tableau Server should the administrator update the credentials so the extract refresh can succeed?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"In the workbook's Permissions settings"},{"id":"b","text":"In the data source's Connection settings on Tableau Server"},{"id":"c","text":"In the Tableau Desktop workbook's Data menu"},{"id":"d","text":"In the Site Settings under Authentication"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$When a published data source's credentials change, the correct place to update them is within the data source's Connection settings on Tableau Server (or Tableau Cloud). This allows the scheduled extract refresh to authenticate with the new credentials. Permissions settings control who can access the data source. Changing credentials in Tableau Desktop would only help if republishing. Site Authentication settings govern Tableau Server user login, not data source connectivity.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/server/en-us/help.htm#datasource_connections.htm","label":"Tableau - Edit Connection Information for a Published Data Source"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau extract is scheduled to refresh every night on Tableau Server, but the underlying source database credentials have changed. Where in Tableau Server should the administrator update the credentials so the extract refresh can succeed?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When using Tableau's relationship model (introduced in Tableau 2020.2), what happens when two tables are related but a row in the primary table has no matching rows in the related table?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The row from the primary table is excluded from all analyses."},{"id":"b","text":"The row from the primary table is preserved and the related fields display null values."},{"id":"c","text":"Tableau automatically fills the missing values with zeroes."},{"id":"d","text":"Tableau converts the relationship to an inner join and drops the unmatched row."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau's relationship model is non-destructive — rows from the primary table are always preserved even when no matching rows exist in the related table. In that case, the fields from the related table will show null. This behavior differs from a traditional inner join, which would drop unmatched rows. Tableau does not automatically substitute zeroes or silently convert relationships to inner joins.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/relate_tables.htm","label":"Tableau - Relate Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$When using Tableau's relationship model (introduced in Tableau 2020.2), what happens when two tables are related but a row in the primary table has no matching rows in the related table?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst has a Tableau extract (.hyper file) that is growing too large and causing performance issues. The analyst only needs data from the last 12 months. Which extract configuration option should the analyst use to reduce the extract size?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Incremental refresh"},{"id":"b","text":"Extract filter"},{"id":"c","text":"Aggregation of visible dimensions"},{"id":"d","text":"Hide unused fields"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$An Extract filter limits which rows are stored in the .hyper file based on specified criteria (e.g., only rows where the date is within the last 12 months), directly reducing the extract size. Incremental refresh adds only new rows since the last refresh but doesn't remove old data. Aggregating visible dimensions can reduce extract size when precise row-level data is not needed, but it doesn't target a date range. Hiding unused fields removes columns, not rows.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau - Extract Your Data - Filters and Options"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst has a Tableau extract (.hyper file) that is growing too large and causing performance issues. The analyst only needs data from the last 12 months. Which extract configuration option should the analyst use to reduce the extract size?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to combine sales data from a Salesforce CRM with inventory data from a MySQL database in a single Tableau view. The two systems have different grain levels and no shared primary key suitable for joining. Which Tableau feature is most appropriate for this scenario?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Union"},{"id":"b","text":"Cross-database join"},{"id":"c","text":"Data blending"},{"id":"d","text":"Extract append"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Data blending is designed precisely for combining data from disparate sources (e.g., Salesforce and MySQL) at the view level when a direct join is impractical, especially when sources have different granularity or no suitable join key. A Union requires identical schema and the same connection type. A Cross-database join can span different databases but still requires a join key and can cause performance issues at different grains. Extract append is not a standard Tableau feature for combining heterogeneous sources.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/multiple_connections.htm","label":"Tableau - Blend Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst needs to combine sales data from a Salesforce CRM with inventory data from a MySQL database in a single Tableau view. The two systems have different grain levels and no shared primary key suitable for joining. Which Tableau feature is most appropriate for this scenario?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$While working in the Tableau Desktop Data Source pane, an analyst uses the 'Pivot' feature on several columns. What does the Pivot transformation accomplish?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It converts row values into separate columns (wide format)."},{"id":"b","text":"It converts selected column headers into row values (long format)."},{"id":"c","text":"It transposes the entire dataset so rows become columns and columns become rows."},{"id":"d","text":"It creates a cross-tabulation of two selected fields."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The Pivot feature in the Tableau Data Source pane reshapes data from wide format to long (narrow) format by turning selected column headers into row values and placing corresponding cell values into a new measure column. This is particularly useful for time-series data stored in wide format (e.g., Jan, Feb, Mar as separate columns). It does not convert rows into columns (that would be unpivoting in reverse), does not transpose the entire table, and does not create cross-tabulations.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/pivot.htm","label":"Tableau - Pivot Data from Columns to Rows"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$While working in the Tableau Desktop Data Source pane, an analyst uses the 'Pivot' feature on several columns. What does the Pivot transformation accomplish?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst connects Tableau to a published data source on Tableau Server. When the analyst opens the workbook later, they notice changes made by a colleague to the published data source are not reflected. What is the most likely reason?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The workbook uses a live connection but Tableau Server is offline."},{"id":"b","text":"The workbook contains an embedded copy of the data source that was not refreshed."},{"id":"c","text":"The colleague published changes to a different site on Tableau Server."},{"id":"d","text":"The analyst's workbook is connected to the published data source but has a local extract override."}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$If a workbook that references a published data source has a local extract override, it will use the locally stored extract rather than the up-to-date published data source. This is a common cause of stale data. An offline server would prevent the workbook from opening at all in a live connection scenario. Publishing to a different site is possible but less likely than a local extract override. Embedded data sources are a separate concept from connecting to a published data source.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/publish_datasources_about.htm","label":"Tableau - Use Published Data Sources"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst connects Tableau to a published data source on Tableau Server. When the analyst opens the workbook later, they notice changes made by a colleague to the published data source are not reflected. What is the most likely reason?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is working with a dataset that has a column called 'Region Code' stored as an integer. The analyst wants Tableau to treat this field as a geographic dimension for mapping purposes. What should the analyst do?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Change the field's data type to String in the Data Source pane."},{"id":"b","text":"Assign the field a Geographic Role of 'NUTS Europe' in the Data pane."},{"id":"c","text":"Change the field's data type to String and assign an appropriate Geographic Role."},{"id":"d","text":"Create a calculated field using the MAKEPOINT() function."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$To use a field for geographic mapping, two steps are typically required: first, ensure the data type is String (since many region codes contain leading zeros or alphanumeric characters), and second, assign the correct Geographic Role in the Data pane (e.g., State/Province, ZIP Code, Country, etc.). Changing the data type alone won't make Tableau recognize it geographically. Assigning a geographic role without fixing the data type may cause matching errors. MAKEPOINT() is used to create spatial points from latitude/longitude coordinates, not for assigning standard geographic roles.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/maps_geographicroles.htm","label":"Tableau - Assign Geographic Roles"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is working with a dataset that has a column called 'Region Code' stored as an integer. The analyst wants Tableau to treat this field as a geographic dimension for mapping purposes. What should the analyst do?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which of the following correctly describes the difference between an incremental extract refresh and a full extract refresh in Tableau?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"An incremental refresh rebuilds the entire extract from scratch, while a full refresh only appends new rows."},{"id":"b","text":"An incremental refresh appends only new rows since the last refresh, while a full refresh rebuilds the entire extract from scratch."},{"id":"c","text":"An incremental refresh can only be used with relational databases, while a full refresh works with all data sources."},{"id":"d","text":"An incremental refresh removes deleted rows and adds new ones, while a full refresh only adds new rows."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A full extract refresh drops the existing .hyper file and rebuilds it entirely from the source data. An incremental refresh appends only the new rows (based on a specified date/integer column) added since the last refresh, making it faster for frequently updated data. Incremental refresh does not remove deleted or updated rows — that requires a full refresh. Both refresh types are available for supported data sources, but incremental refresh has specific requirements.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_refresh.htm","label":"Tableau - Refresh Extracts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which of the following correctly describes the difference between an incremental extract refresh and a full extract refresh in Tableau?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to use Tableau Prep Builder to clean a dataset before connecting it to Tableau Desktop. The analyst needs to remove leading and trailing spaces from a string field called 'Customer Name'. Which Tableau Prep transformation should be used?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Group and Replace"},{"id":"b","text":"Clean step — Trim Spaces"},{"id":"c","text":"Filter step with a NOT CONTAINS condition"},{"id":"d","text":"Aggregate step with a TRIM calculation"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$In Tableau Prep Builder, the Clean step provides built-in data cleaning operations including 'Trim Spaces', which automatically removes leading and trailing whitespace from string fields. Group and Replace is used to manually or automatically group similar values (e.g., spelling variations). A Filter step with NOT CONTAINS cannot remove spaces from within a value. An Aggregate step is used to summarize data, not to clean string values.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/prep/en-us/prep_clean.htm","label":"Tableau Prep - Clean and Shape Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to use Tableau Prep Builder to clean a dataset before connecting it to Tableau Desktop. The analyst needs to remove leading and trailing spaces from a string field called 'Customer Name'. Which Tableau Prep transformation should be used?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to connect Tableau Desktop to data exposed through a REST API that does not have a native Tableau connector. Which built-in Tableau connection method should the analyst use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"OData connector"},{"id":"b","text":"Web Data Connector (WDC)"},{"id":"c","text":"Cross-database join"},{"id":"d","text":"Published data source"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The Web Data Connector (WDC) framework allows developers and analysts to build custom connectors that pull data from web services and REST APIs into Tableau Desktop. OData is a specific protocol and connector for OData-compliant services, not generic REST APIs. A Cross-database join connects tables across different databases but does not connect to web APIs. A Published data source is a way to share an existing data source, not a method for creating a new API connection.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/examples_web_data_connector.htm","label":"Tableau - Web Data Connector Overview"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst needs to connect Tableau Desktop to data exposed through a REST API that does not have a native Tableau connector. Which built-in Tableau connection method should the analyst use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau Desktop's logical layer of the data model, what is the primary purpose of defining a relationship between two tables rather than joining them directly?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Relationships always produce faster query results than joins."},{"id":"b","text":"Relationships allow Tableau to generate appropriate join types dynamically based on the fields used in the view, preserving row counts in each table."},{"id":"c","text":"Relationships replace the need for calculated fields entirely."},{"id":"d","text":"Relationships allow two tables to be merged into a single flat table automatically."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau's relationship model in the logical layer uses context-aware, dynamic joins — Tableau determines the appropriate join type at query time based on which fields are used in the view. This approach preserves the native granularity of each table and avoids duplicate or missing data that can arise from premature joins. Relationships are not always faster than joins; performance depends on context. They do not eliminate the need for calculated fields and do not merge tables into a flat structure.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/relate_tables.htm","label":"Tableau - How Relationships Differ from Joins"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau Desktop's logical layer of the data model, what is the primary purpose of defining a relationship between two tables rather than joining them directly?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst wants to identify which product subcategories are driving profit loss. They drag Subcategory to Rows and Profit to Columns, then sort descending. Which additional analytical feature should they enable to instantly highlight subcategories below zero profit without creating a calculated field?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Add a constant reference line at zero on the Profit axis"},{"id":"b","text":"Enable 'Show Mark Labels' on the bar chart"},{"id":"c","text":"Apply a stepped color palette from the Marks card"},{"id":"d","text":"Use the Totals option under Analysis menu"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Adding a constant reference line at zero on the Profit axis provides an immediate visual divider that separates profitable subcategories from unprofitable ones without requiring a calculated field. Mark labels (b) show values but do not highlight negative values distinctly. A stepped color palette (c) requires mapping a color measure to the Marks card, not just a reference line. Totals (d) aggregates data and does not highlight individual subcategory performance relative to zero.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/reference_lines.htm","label":"Tableau – Add Reference Lines, Bands, Distributions, and Boxes"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst wants to identify which product subcategories are driving profit loss. They drag Subcategory to Rows and Profit to Columns, then sort descending. Which additional analytical feature should they enable to instantly highlight subcategories below zero profit without creating a calculated field?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is building a view and needs to compare each region's sales to the overall average sales across all regions. Which Tableau feature accomplishes this most efficiently?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A table calculation using WINDOW_AVG(SUM([Sales]))"},{"id":"b","text":"A Level of Detail (LOD) expression: { FIXED : AVG([Sales]) }"},{"id":"c","text":"A reference line set to Average using the entire table scope"},{"id":"d","text":"Dragging the Average Line option from the Analytics pane"}]$json$::jsonb, $json$["d"]$json$::jsonb, $patch$Dragging an Average Line from the Analytics pane is the most efficient method because it requires no formula authoring and automatically computes and displays the average across all marks in scope. LOD expressions (b) would compute a fixed average but require embedding in a calculation. WINDOW_AVG (a) is a valid table calculation but requires writing a formula. A manual reference line (c) set to Average is also valid but 'Average Line' from the Analytics pane is a direct drag-and-drop equivalent that is faster and purpose-built for this use case.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/analytics_pane.htm","label":"Tableau – Analytics Pane"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
