INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data analyst uses the following LOD expression in a view filtered by Region: { FIXED [Customer Name] : SUM([Sales]) }. Which statement correctly describes how this expression behaves when a Region filter is applied?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The FIXED LOD respects the Region filter because dimension filters always override FIXED expressions"},{"id":"b","text":"The FIXED LOD ignores the Region filter unless the Region filter is added to the Context"},{"id":"c","text":"The FIXED LOD automatically respects all filters regardless of filter type"},{"id":"d","text":"The FIXED LOD ignores all filters including context filters"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$FIXED LOD expressions are computed before dimension filters in Tableau's order of operations. Therefore, a standard dimension filter on Region will be ignored by the FIXED LOD. To make the FIXED LOD respect a filter, the filter must be promoted to a Context Filter (right-click > Add to Context). Option (a) is incorrect because dimension filters do not override FIXED LODs by default. Option (c) is wrong; FIXED ignores non-context dimension filters. Option (d) is wrong because context filters ARE respected by FIXED LODs.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau – Level of Detail Expressions"},{"url":"https://help.tableau.com/current/pro/desktop/en-us/order_of_operations.htm","label":"Tableau – Order of Operations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
