INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to display a forecast for the next 6 months of sales based on historical monthly data. Which Tableau built-in feature should they use, and what is a key requirement for it to function?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Analytics pane Forecast feature; requires a date dimension with at least 5 seasonal cycles of data"},{"id":"b","text":"Analytics pane Forecast feature; requires a continuous date dimension and at least one measure in the view"},{"id":"c","text":"A trend line with a linear model; works on any numeric axis regardless of date fields"},{"id":"d","text":"A parameter control for future dates; requires manual input of projected values"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau's built-in Forecast feature (accessible from the Analytics pane) requires a continuous date dimension on the view and at least one measure to project. It uses exponential smoothing models to extrapolate future values. Option (a) is partially correct about needing date data, but the minimum requirement is not '5 seasonal cycles' — Tableau recommends sufficient historical data but the hard requirement is a date field and measure. Option (c) describes a trend line extension, which is not the same as a time-series forecast. Option (d) is a manual workaround, not a built-in forecast feature.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/forecast_create.htm","label":"Tableau – Create a Forecast"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst needs to display a forecast for the next 6 months of sales based on historical monthly data. Which Tableau built-in feature should they use, and what is a key requirement for it to function?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which of the following best describes the purpose of a 'cluster' analysis when dragged from the Analytics pane in Tableau?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It applies a K-means algorithm to group marks into a specified number of clusters based on selected measures"},{"id":"b","text":"It groups dimension members alphabetically into equal-sized bins"},{"id":"c","text":"It creates a hierarchical drill-down grouping of marks based on a date dimension"},{"id":"d","text":"It applies a linear regression to segment data into high and low value groups"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Tableau's Cluster feature in the Analytics pane uses a K-means clustering algorithm to automatically group marks into a user-specified number of clusters based on the measures present in the view. This is an unsupervised machine learning technique for exploratory analysis. Option (b) describes binning, not clustering. Option (c) describes date hierarchy drilling, unrelated to clusters. Option (d) describes a regression-based segmentation, not K-means clustering.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/clusters.htm","label":"Tableau – Find Clusters in Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which of the following best describes the purpose of a 'cluster' analysis when dragged from the Analytics pane in Tableau?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is working with a large dataset and wants to apply a filter that is computed before LOD expressions in Tableau's order of operations. Which type of filter should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A dimension filter added via the Filters shelf"},{"id":"b","text":"A measure filter applied using an aggregate condition"},{"id":"c","text":"A context filter created by right-clicking a filter and selecting 'Add to Context'"},{"id":"d","text":"A table calculation filter applied to a computed field"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$In Tableau's order of operations, context filters execute before LOD expressions (FIXED, INCLUDE, EXCLUDE), which in turn execute before dimension filters. By promoting a filter to a context filter, it is processed at the data source level before LOD computations occur. Standard dimension filters (a) are applied after LOD expressions. Measure filters (b) are applied after dimension filters. Table calculation filters (d) are applied last in the order of operations.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/order_of_operations.htm","label":"Tableau – Order of Operations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is working with a large dataset and wants to apply a filter that is computed before LOD expressions in Tableau's order of operations. Which type of filter should they use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst uses the DATEDIFF function in a calculated field: DATEDIFF('month', [Order Date], [Ship Date]). What does this expression return?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The number of days between Order Date and Ship Date"},{"id":"b","text":"The number of complete calendar months between Order Date and Ship Date"},{"id":"c","text":"A Boolean indicating whether the shipment occurred within the same month as the order"},{"id":"d","text":"The formatted string difference between the two dates in month notation"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$DATEDIFF('month', start_date, end_date) in Tableau returns the number of complete month boundaries crossed between the two dates, represented as an integer. For example, January 31 to February 1 would return 1 month. Option (a) would require 'day' as the date part. Option (c) describes a Boolean logic check, not what DATEDIFF returns. Option (d) is incorrect; DATEDIFF always returns an integer, not a formatted string.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_date.htm","label":"Tableau – Date Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst uses the DATEDIFF function in a calculated field: DATEDIFF('month', [Order Date], [Ship Date]). What does this expression return?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to show the percentage contribution of each product category to total sales, where the total is always the grand total regardless of any filters applied in the view. Which approach achieves this correctly?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A table calculation: SUM([Sales]) / TOTAL(SUM([Sales])) scoped to Table"},{"id":"b","text":"A FIXED LOD: SUM([Sales]) / { FIXED : SUM([Sales]) }"},{"id":"c","text":"A quick table calculation: Percent of Total computed using Table (Down)"},{"id":"d","text":"A reference line showing percentage contribution on the axis"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Using a FIXED LOD expression { FIXED : SUM([Sales]) } computes the grand total sales across the entire dataset, independent of any dimension filters (unless context filters are used). Dividing SUM([Sales]) by this FIXED total gives the true percentage of grand total regardless of view filters. Option (a) uses TOTAL(), which respects the current filter context. Option (c) is a quick table calculation that also respects view filters and changes scope with the table layout. Option (d) shows a reference annotation, not a per-mark percentage.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau – Level of Detail Expressions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to show the percentage contribution of each product category to total sales, where the total is always the grand total regardless of any filters applied in the view. Which approach achieves this correctly?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Tableau feature should an analyst use to allow end users to interactively change the aggregation type (e.g., switch between SUM, AVG, and MEDIAN) of a measure displayed in a view?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A filter action connected to a separate summary sheet"},{"id":"b","text":"A parameter with a string data type combined with a CASE calculated field"},{"id":"c","text":"A set action applied to a measure field"},{"id":"d","text":"Enabling 'Measure Names' on the Filters shelf"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Creating a string parameter (e.g., with allowed values 'SUM', 'AVG', 'MEDIAN') and referencing it in a CASE calculated field (e.g., CASE [Agg Type] WHEN 'SUM' THEN SUM([Sales]) WHEN 'AVG' THEN AVG([Sales]) END) allows users to interactively switch aggregation methods. Filter actions (a) filter data, not aggregation type. Set actions (c) modify set membership for dimensions, not measure aggregation. Measure Names on the Filters shelf (d) shows/hides measures but does not change their aggregation.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/parameters_create.htm","label":"Tableau – Create Parameters"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Tableau feature should an analyst use to allow end users to interactively change the aggregation type (e.g., switch between SUM, AVG, and MEDIAN) of a measure displayed in a view?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is examining a dual-axis chart where the secondary axis is not aligned with the primary axis, causing the chart to be visually misleading. Which action should the analyst take to fix this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Right-click the secondary axis and select 'Synchronize Axis'"},{"id":"b","text":"Change the mark type of the secondary axis to Bar"},{"id":"c","text":"Move the secondary measure to the same axis as the primary measure"},{"id":"d","text":"Apply a table calculation to normalize both axes to the same scale"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Right-clicking the secondary axis and selecting 'Synchronize Axis' forces the secondary axis to use the same scale and range as the primary axis, eliminating the visual misalignment that can mislead viewers. Changing the mark type (b) affects visual encoding, not axis alignment. Moving to the same axis (c) would combine the measures on one axis, removing the dual-axis structure entirely. A normalization table calculation (d) could work mathematically but is not the direct, built-in solution for axis synchronization.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/multiplemeasures_dualaxes.htm","label":"Tableau – Dual Axis Charts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is examining a dual-axis chart where the secondary axis is not aligned with the primary axis, causing the chart to be visually misleading. Which action should the analyst take to fix this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst is building a dashboard for a retail client and needs to display a geographic breakdown of sales by state. Which chart type in Tableau is MOST appropriate for visualizing this data?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Heat map"},{"id":"b","text":"Filled map (choropleth)"},{"id":"c","text":"Treemap"},{"id":"d","text":"Bullet chart"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A filled map (choropleth) shades geographic regions—such as states—based on a measure value, making it the ideal chart type for visualizing sales distribution across states. Heat maps use color intensity on a matrix of dimensions, treemaps use nested rectangles, and bullet charts compare a measure to a target—none of these convey geographic context.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/maps_build.htm","label":"Tableau – Map Chart Types"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst is building a dashboard for a retail client and needs to display a geographic breakdown of sales by state. Which chart type in Tableau is MOST appropriate for visualizing this data?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When building a Tableau worksheet, an analyst wants to compare the proportion of sales contributed by each product sub-category to the whole. Which Show Me chart type is BEST suited for this purpose?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Side-by-side bars"},{"id":"b","text":"Scatter plot"},{"id":"c","text":"Pie chart"},{"id":"d","text":"Box-and-whisker plot"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A pie chart encodes part-to-whole relationships by displaying each category as a slice proportional to its contribution to the total. Side-by-side bars compare absolute values across categories, scatter plots show relationships between two measures, and box-and-whisker plots show statistical distributions—none of these directly communicate part-to-whole proportion as clearly as a pie chart for a small number of categories.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/what_chart_do_i_have.htm","label":"Tableau – Choose the Right Chart Type"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
