  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$When building a Tableau worksheet, an analyst wants to compare the proportion of sales contributed by each product sub-category to the whole. Which Show Me chart type is BEST suited for this purpose?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst creates a calculated field using the formula IF [Profit] > 0 THEN 'Profitable' ELSE 'Unprofitable' END. When this field is placed on the Color shelf, what will happen?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Tableau will display a continuous color gradient based on profit values."},{"id":"b","text":"Tableau will encode marks with two discrete colors—one for 'Profitable' and one for 'Unprofitable'."},{"id":"c","text":"Tableau will throw an error because string fields cannot be placed on the Color shelf."},{"id":"d","text":"Tableau will automatically convert the string values to numeric codes for coloring."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The calculated field returns a string dimension ('Profitable' or 'Unprofitable'). When a discrete string dimension is placed on the Color shelf, Tableau assigns a distinct color to each member of the dimension—resulting in two colors for the two category values. String fields are valid on the Color shelf; Tableau does not throw an error. Continuous gradients apply only to continuous (numeric/date) measures.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/viewparts_marks_marktypes.htm","label":"Tableau – Color, Size, and Shape Marks"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
