  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst creates a calculated field using the formula IF [Profit] > 0 THEN 'Profitable' ELSE 'Unprofitable' END. When this field is placed on the Color shelf, what will happen?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau developer wants to display the top 10 customers by total sales on a bar chart. Which feature should be used to achieve this without creating a separate data source?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Context filter"},{"id":"b","text":"Top filter on the Customer Name dimension"},{"id":"c","text":"A FIXED level-of-detail expression"},{"id":"d","text":"A table calculation using RANK()"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau's Top/Bottom filter (available when right-clicking a dimension in Filters or using the Top tab in the Filter dialog) allows the analyst to limit the view to the top N members by a specified measure—in this case, the top 10 customers by sum of sales. A context filter defines a filtering context but does not inherently limit to a top N. A FIXED LOD and a RANK() table calculation can produce similar results but require additional configuration steps and are not the most direct built-in solution for this use case.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/filtering_top.htm","label":"Tableau – Filter Top and Bottom Values"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
