  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau developer wants to display the top 10 customers by total sales on a bar chart. Which feature should be used to achieve this without creating a separate data source?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to add a reference line showing the average profit across all marks in a view. Where in Tableau Desktop can the analyst add this reference line?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"From the Analytics pane, drag 'Average Line' to the view"},{"id":"b","text":"By adding AVG([Profit]) as a second measure on the Rows shelf"},{"id":"c","text":"By right-clicking the axis and selecting 'Add Trend Line'"},{"id":"d","text":"From the Data pane, drag 'Profit' to the Detail shelf"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$The Analytics pane in Tableau Desktop provides drag-and-drop access to reference lines, trend lines, box plots, and other statistical objects. Dragging 'Average Line' from the Analytics pane directly onto the view adds a reference line at the average value of the relevant measure. Adding a second measure to the Rows shelf creates a dual-axis or separate pane—not a reference line. 'Add Trend Line' in the axis right-click menu adds a statistical trend line, not a simple average reference line. Placing a field on Detail adds granularity but does not draw a reference line.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/reference_lines.htm","label":"Tableau – Add Reference Lines, Bands, Distributions, and Box Plots"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
