  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst needs to add a reference line showing the average profit across all marks in a view. Where in Tableau Desktop can the analyst add this reference line?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst wants to allow dashboard viewers to dynamically switch the measure displayed in a bar chart between 'Sales', 'Profit', and 'Quantity' without using separate sheets. Which Tableau feature enables this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Parameter with a calculated field"},{"id":"b","text":"A set action"},{"id":"c","text":"A context filter"},{"id":"d","text":"A data source filter"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$A parameter in Tableau can hold a user-selected value (e.g., 'Sales', 'Profit', 'Quantity'). A companion calculated field referencing the parameter (using CASE or IF logic) then returns the corresponding measure value. Placing the calculated field on the view allows dynamic measure switching. Set actions control which members are in a set (typically for dimension filtering), context filters restrict the data pool, and data source filters apply static restrictions at the data layer—none of these enable measure switching.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/parameters_create.htm","label":"Tableau – Create Parameters"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
