  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst wants to allow dashboard viewers to dynamically switch the measure displayed in a bar chart between 'Sales', 'Profit', and 'Quantity' without using separate sheets. Which Tableau feature enables this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When constructing a dashboard in Tableau, what is the primary purpose of a Layout Container?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"To define the data source connection for objects placed inside it"},{"id":"b","text":"To group and organize dashboard objects so they resize and reposition together"},{"id":"c","text":"To apply a uniform color palette to all sheets placed inside it"},{"id":"d","text":"To restrict viewer permissions to the objects within the container"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Layout Containers (Horizontal and Vertical) in Tableau dashboards allow objects such as sheets, text boxes, and images to be grouped together. When the container resizes—due to a device layout change or window resize—the objects inside it resize and reposition proportionally. Containers do not affect data connections, color palettes, or permissions.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/dashboards_create.htm","label":"Tableau – Build Dashboards"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
