INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst has a dual-axis chart with two measures on the same axis scale. After synchronizing the axes, one measure's bars appear very small. What is the MOST likely cause?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The two measures have very different value ranges, and synchronizing forces both axes to share the larger range."},{"id":"b","text":"Synchronizing axes removes all color encoding from the smaller measure."},{"id":"c","text":"The dual axis feature is incompatible with bar chart mark types."},{"id":"d","text":"Tableau automatically applies a logarithmic scale when axes are synchronized."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Synchronizing dual axes forces both axes to use the same minimum and maximum values. If one measure ranges from 0–1,000 and the other from 0–1,000,000, the synchronized axis uses 0–1,000,000, making the smaller-range measure's bars appear very small relative to the larger measure. Synchronizing axes does not affect color, mark types, or scales in the logarithmic sense by default.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/qs_dual_axes.htm","label":"Tableau – Dual Axis Charts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
