  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst has a dual-axis chart with two measures on the same axis scale. After synchronizing the axes, one measure's bars appear very small. What is the MOST likely cause?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst wants to highlight specific marks in a view based on a user's selection while keeping all other marks visible but dimmed. Which dashboard feature BEST accomplishes this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Filter action"},{"id":"b","text":"Highlight action"},{"id":"c","text":"URL action"},{"id":"d","text":"Set action"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Highlight action in Tableau visually emphasizes marks that match the selected field values while dimming (graying out) non-matching marks—all marks remain in the view. A Filter action removes non-matching marks from the view entirely. A URL action opens a webpage. A Set action adds or removes members from a set but does not inherently produce a highlight/dim effect across all marks.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/actions_highlight.htm","label":"Tableau – Highlight Actions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
