  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst wants to highlight specific marks in a view based on a user's selection while keeping all other marks visible but dimmed. Which dashboard feature BEST accomplishes this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to create a view that shows year-over-year sales growth as a percentage, computed relative to each mark's position in the view. Which Tableau feature is MOST appropriate?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A FIXED level-of-detail expression"},{"id":"b","text":"A quick table calculation using 'Percent Difference From'"},{"id":"c","text":"A data source filter limiting data to two years"},{"id":"d","text":"A parameter controlling which year is displayed"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Quick table calculations in Tableau include 'Percent Difference From', which computes the percentage change between consecutive values along a specified direction (e.g., across years). This calculation is applied post-aggregation, relative to mark positions in the view, making it ideal for year-over-year growth. A FIXED LOD expression computes at a specific grain regardless of the view, a data source filter restricts data, and a parameter controls user selections—none of these directly compute percent difference between periods.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_tablecalculations_quick.htm","label":"Tableau – Quick Table Calculations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
