INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau developer wants to display sales data on a dashboard where the time granularity (Day, Month, Quarter, Year) can be changed by the viewer at runtime. Which combination of features supports this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A date filter with relative date options"},{"id":"b","text":"A parameter controlling a DATETRUNC calculated field"},{"id":"c","text":"A context filter applied to the Order Date field"},{"id":"d","text":"A fixed LOD expression using DATEPART"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A string or list parameter that holds values such as 'day', 'month', 'quarter', 'year' can be used inside a DATETRUNC() calculated field (e.g., DATETRUNC([Date Granularity Parameter], [Order Date])). When viewers change the parameter value, the date truncation level updates dynamically, effectively changing the time granularity of the view. A relative date filter restricts the date range but does not change granularity. A context filter restricts data. A fixed LOD with DATEPART calculates at a fixed level and cannot be changed at runtime by a viewer.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_date.htm","label":"Tableau – DATETRUNC Function"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
