INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Tableau mark type allows an analyst to encode both a measure value and a secondary measure value on the same mark using size and color simultaneously on a scatter plot?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Circle mark type with measures on Size and Color shelves"},{"id":"b","text":"Bar mark type with measures on Rows and Columns shelves"},{"id":"c","text":"Text mark type with measures on Label and Detail shelves"},{"id":"d","text":"Line mark type with measures on Path and Color shelves"}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$A scatter plot uses the Circle (or Shape) mark type, where X and Y positions encode two measures via Columns and Rows. Placing a third measure on the Size shelf encodes bubble size, and placing a fourth measure (or dimension) on the Color shelf encodes color—creating a bubble chart that communicates four variables simultaneously. Bar marks encode magnitude along a single axis; text marks encode labels; line marks encode sequential/temporal trends—none of these combine size and color in a scatter context as effectively.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/viewparts_marks_markproperties.htm","label":"Tableau – Marks Card"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Tableau mark type allows an analyst to encode both a measure value and a secondary measure value on the same mark using size and color simultaneously on a scatter plot?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is building a Tableau story and wants each story point to focus on a different region's performance using the same base worksheet. What is the MOST efficient approach?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Duplicate the worksheet once for each region and add each duplicate as a separate story point."},{"id":"b","text":"Use a single worksheet and apply a different filter for each story point by saving annotated views as story point captions."},{"id":"c","text":"Use a single worksheet, add it to each story point, and apply a different filter or highlight per story point using the story point navigator."},{"id":"d","text":"Embed a separate dashboard for each region and link the dashboards with URL actions."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$In Tableau Stories, you can add the same worksheet to multiple story points and configure a different filter or highlighted view for each story point. This avoids worksheet duplication and keeps maintenance simple—changes to the underlying worksheet propagate to all story points. Duplicating the worksheet per region creates maintenance overhead. Saving annotated views as captions does not actually filter the data per story point. Embedding separate dashboards via URL actions is overly complex and not a native story feature.$patch$, $patch$Create Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/stories.htm","label":"Tableau – Create a Story"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
