  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau's order of operations, which filter type is evaluated BEFORE FIXED LOD expressions?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Dimension filters"},{"id":"b","text":"Measure filters"},{"id":"c","text":"Context filters"},{"id":"d","text":"Table calculation filters"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$According to the source material, the order of operations is: Extract filters → Data source filters → Context filters → FIXED LODs → Dimension filters → INCLUDE/EXCLUDE LODs → Measure filters → Table calcs. Context filters come before FIXED LODs, meaning they constrain what data FIXED LODs see.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/order_of_operations.htm","label":"Tableau Order of Operations"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
