INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When publishing a workbook to Tableau Server, an analyst wants to ensure that an embedded data source credential is stored on the server so that scheduled extract refreshes can run without user intervention. Which credential option in the publish dialog achieves this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Prompt user"},{"id":"b","text":"No credentials"},{"id":"c","text":"Embedded password"},{"id":"d","text":"Use Viewer credentials"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Selecting 'Embedded password' stores the data source credentials within the published content on Tableau Server, allowing scheduled extract refreshes to run automatically without prompting a user. 'Prompt user' requires each viewer to supply credentials at runtime, which breaks automated schedules. 'No credentials' applies only to data sources that require no authentication. 'Use Viewer credentials' passes the viewer's own credentials for live connections and is not suitable for scheduled refreshes.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/publishing_sharing_authentication.htm","label":"Tableau Help – Set Credentials for Accessing Published Data Sources"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
