INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst published a workbook to a Tableau Cloud project that is set to 'Locked' permissions. A colleague reports they cannot view the workbook even though they were granted Viewer permission directly on the workbook. Why is the colleague unable to view it?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The colleague must have at least an Explorer site role to view any content."},{"id":"b","text":"Locked projects enforce permissions set at the project level and override any individual content permissions."},{"id":"c","text":"The workbook requires an embedded password that the colleague does not know."},{"id":"d","text":"Tableau Cloud does not allow permission inheritance from workbooks to users."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$When a project's permission mode is set to 'Locked', all content inside the project inherits and is governed exclusively by the permissions defined at the project level. Individual permissions granted directly on a workbook within a locked project are ignored. This is by design so administrators can enforce consistent access control. A Viewer site role is sufficient to view content; no Explorer role is required. The issue is not related to embedded passwords or inheritance direction.$patch$, $patch$Publish and Manage Content$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/server/en-us/permissions.htm#lock-permissions","label":"Tableau Help – Locked vs. Customizable Project Permissions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P4'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst published a workbook to a Tableau Cloud project that is set to 'Locked' permissions. A colleague reports they cannot view the workbook even though they were granted Viewer permission directly on the workbook. Why is the colleague unable to view it?$patch$);
