  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A calculated field uses the expression: IIF(ISNULL([Discount]), 0, [Discount]). Which built-in function could replace this expression entirely with a more concise equivalent?$patch$);
