INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to combine customer transaction data from two tables in a live SQL Server connection. The first table contains all transactions from 2022, and the second contains all transactions from 2023. Both tables have identical schemas. Which Tableau feature is MOST appropriate to combine these two tables while keeping a live connection?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Cross-database join"},{"id":"b","text":"Data blend"},{"id":"c","text":"Union"},{"id":"d","text":"Relationship"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A Union appends rows from two or more tables with identical or similar schemas, which is exactly what is needed when combining yearly transaction tables. A Join merges columns, a Blend works across separate data sources, and a Relationship is used to link tables logically. Union is the correct choice for stacking rows from identically structured tables.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/union.htm","label":"Tableau – Union Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
