INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$When using Tableau's physical layer to define a relationship between an Orders table and a Returns table, what is the default join type Tableau uses when querying the related tables at runtime?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"INNER JOIN"},{"id":"b","text":"LEFT JOIN"},{"id":"c","text":"FULL OUTER JOIN"},{"id":"d","text":"CROSS JOIN"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau relationships use a context-aware querying mechanism that generates FULL OUTER JOINs behind the scenes to preserve all data from both tables and avoid unintended row duplication or data loss. This is different from traditional joins where you must explicitly choose join type. INNER, LEFT, and CROSS joins are not the default behavior for Tableau relationships.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/relate_tables.htm","label":"Tableau – How Relationships Differ from Joins"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$When using Tableau's physical layer to define a relationship between an Orders table and a Returns table, what is the default join type Tableau uses when querying the related tables at runtime?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A data analyst is working with a text file (.csv) that uses a pipe character (|) as the delimiter. When connecting to the file in Tableau Desktop, the data appears in a single column. What should the analyst do to resolve this?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Convert the file to .xlsx format before connecting."},{"id":"b","text":"Use a custom SQL query to split the column."},{"id":"c","text":"Open the Text File connection settings and change the field separator to the pipe character."},{"id":"d","text":"Create a calculated field using the SPLIT() function to separate the values."}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau allows you to specify the field separator (delimiter) when connecting to a text file. Changing it to the pipe character (|) in the connection dialog will correctly parse the file into separate columns. Converting the file is unnecessary extra work. Custom SQL and calculated fields are workarounds that are less efficient than simply correcting the delimiter at the connection level.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/examples_text.htm","label":"Tableau – Connect to a Text File"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A data analyst is working with a text file (.csv) that uses a pipe character (|) as the delimiter. When connecting to the file in Tableau Desktop, the data appears in a single column. What should the analyst do to resolve this?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst wants to improve dashboard query performance by storing a processed snapshot of data directly in the Tableau workbook. The data source is a slow-responding Oracle database. Which approach should the analyst use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Switch from a live connection to an extract (.hyper file)."},{"id":"b","text":"Use a cross-database join to merge the Oracle tables."},{"id":"c","text":"Enable context filters on all dimensions."},{"id":"d","text":"Publish the workbook to Tableau Public."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Tableau Extracts (.hyper files) store a compressed, optimized snapshot of data locally, which dramatically improves query performance compared to live database connections. Cross-database joins do not address performance against a slow database. Context filters can improve query speed but do not eliminate the live database round-trip. Publishing to Tableau Public does not resolve the underlying performance issue.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau – Extract Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst wants to improve dashboard query performance by storing a processed snapshot of data directly in the Tableau workbook. The data source is a slow-responding Oracle database. Which approach should the analyst use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau's data source page, an analyst applies a data source filter. What is the PRIMARY effect of this filter compared to a view-level filter?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"A data source filter restricts data before it is available to any sheet in the workbook, reducing the data footprint."},{"id":"b","text":"A data source filter is applied after aggregation, while a view-level filter is applied before aggregation."},{"id":"c","text":"A data source filter only affects extracts, not live connections."},{"id":"d","text":"A data source filter removes columns from the data source, while view-level filters remove rows."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$Data source filters restrict rows at the data source level, meaning only the filtered subset of data is available across all worksheets in the workbook. This reduces memory usage and can improve performance. Unlike view-level filters, they are not applied post-aggregation—they filter raw data before it reaches any visualization. They work on both live connections and extracts, and they filter rows, not columns.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/filtering_datasource.htm","label":"Tableau – Filter Data from Data Sources"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau's data source page, an analyst applies a data source filter. What is the PRIMARY effect of this filter compared to a view-level filter?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is using Tableau Prep Builder to clean a dataset. Several rows have NULL values in the 'Revenue' field. The analyst wants to replace all NULLs with the value 0. Which Tableau Prep feature should be used?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Use a Filter step to remove rows where Revenue is NULL."},{"id":"b","text":"Use a Clean step and apply a Replace NULL Values operation."},{"id":"c","text":"Use a Join step with a lookup table that maps NULL to 0."},{"id":"d","text":"Use an Aggregate step and set Revenue's aggregation to SUM."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$In Tableau Prep Builder, the Clean step provides a 'Replace NULL Values' option that allows you to substitute NULL entries with a specified value such as 0. Filtering removes rows entirely rather than replacing values. A join with a lookup table is an overly complex workaround. An aggregate step changes granularity and does not handle NULL replacement at the row level.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/prep/en-us/prep_clean.htm","label":"Tableau Prep – Clean and Shape Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
