  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is using Tableau Prep Builder to clean a dataset. Several rows have NULL values in the 'Revenue' field. The analyst wants to replace all NULLs with the value 0. Which Tableau Prep feature should be used?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst needs to join an Orders table (in SQL Server) with a Product Lookup table (in a Google Sheets file). Which Tableau feature supports this scenario?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Union"},{"id":"b","text":"Cross-database join"},{"id":"c","text":"Data blend"},{"id":"d","text":"Tableau Relationship"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A cross-database join in Tableau allows joining tables from different data source types (e.g., SQL Server and Google Sheets) in a single data source. A union stacks rows from similar schemas. A data blend uses separate data sources linked by a dimension at the view level, which is less precise. Relationships in the logical layer can work across connections but cross-database joins explicitly handle joining tables from different connectors in the physical layer.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/joining_tables.htm","label":"Tableau – Join Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
