INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau Desktop, which wildcard character is used in the 'Wildcard' tab of the Union dialog to automatically include all sheets whose names match a specific pattern?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"%"},{"id":"b","text":"?"},{"id":"c","text":"*"},{"id":"d","text":"#"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Tableau's Wildcard Union uses the asterisk (*) character to match one or more characters in sheet or table names. For example, entering 'Sales*' would match sheets named Sales2022, Sales2023, etc. The percent sign (%) is used as a wildcard in SQL LIKE clauses but not in Tableau's wildcard union. The question mark and hash are not supported wildcard characters in this context.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/union.htm","label":"Tableau – Union Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
