INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst notices that after performing an inner join between an Orders table and a Customers table on 'Customer ID', the resulting row count is LOWER than the Orders table alone. What is the MOST likely explanation?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Some Customer IDs in the Orders table do not exist in the Customers table."},{"id":"b","text":"The join created duplicate rows that Tableau automatically removed."},{"id":"c","text":"Tableau applies a default TOP 100 row limit on all joins."},{"id":"d","text":"The Customers table has fewer columns, causing rows to be dropped."}]$json$::jsonb, $json$["a"]$json$::jsonb, $patch$An INNER JOIN only returns rows where matching values exist in both tables. If some Customer IDs in the Orders table have no corresponding entry in the Customers table, those orders are excluded from the result, reducing the row count. Tableau does not automatically remove duplicates from joins or apply a default row limit. Column count differences do not cause rows to be dropped.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/joining_tables.htm","label":"Tableau – Join Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
