INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst is connecting to a large Snowflake table. To avoid scanning the entire table during development, the analyst wants Tableau to retrieve only a sample of rows. Which Tableau feature enables this during the data connection setup?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Data source filter"},{"id":"b","text":"Extract with sampling"},{"id":"c","text":"Initial SQL statement"},{"id":"d","text":"Connection-level row limit via 'Custom SQL' with a LIMIT clause"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau's Extract dialog offers a Sampling option that retrieves a subset of rows (either by number of rows or a percentage) from the source, which is useful during development to avoid scanning large tables. A data source filter limits rows by condition but requires specifying criteria. An Initial SQL runs a script before the session but doesn't sample data. Custom SQL with LIMIT could work but is a manual workaround rather than Tableau's built-in sampling feature.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau – Extract Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst is connecting to a large Snowflake table. To avoid scanning the entire table during development, the analyst wants Tableau to retrieve only a sample of rows. Which Tableau feature enables this during the data connection setup?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau, what does the 'Sheet' column that appears automatically after performing a Wildcard Union represent?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It indicates the order in which each row was appended during the union."},{"id":"b","text":"It identifies the source sheet or table name from which each row originated."},{"id":"c","text":"It stores the file path of the original data source for each row."},{"id":"d","text":"It is a system-generated row ID unique to each record in the union."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$When a Wildcard Union is created in Tableau, a 'Sheet' (or 'Table Name') field is automatically generated. This field captures the name of the source sheet or file from which each row originated, allowing analysts to filter, group, or trace data back to its original source. It does not represent row order, file paths, or unique row IDs.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/union.htm","label":"Tableau – Union Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau, what does the 'Sheet' column that appears automatically after performing a Wildcard Union represent?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A Tableau analyst wants to connect to a data source that will always reflect the most up-to-date records without any manual refresh. Which connection type should the analyst use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Extract (.hyper file)"},{"id":"b","text":"Live connection"},{"id":"c","text":"Tableau Prep flow output"},{"id":"d","text":"Incremental extract refresh"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A Live connection issues real-time queries directly against the source database, so every view reflects the latest data without any refresh step. An Extract (.hyper file) is an in-memory snapshot that requires a refresh to pick up new data. An incremental extract refresh updates only new rows but still requires scheduling. A Prep flow output produces a static extract. The source material states: 'Live (real-time query against source) vs Extract (.hyper file, in-memory snapshot, faster, supports incremental refresh).'$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/extracting_data.htm","label":"Tableau Help – Live connections vs Extracts"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A Tableau analyst wants to connect to a data source that will always reflect the most up-to-date records without any manual refresh. Which connection type should the analyst use?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst must combine sales data stored in a SQL Server table with quota data stored in a separate Excel workbook. Both tables share a Region key, but the granularity of the Excel data differs from the SQL Server data. Which Tableau feature is most appropriate for this scenario?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Cross-database join"},{"id":"b","text":"Union"},{"id":"c","text":"Data blending"},{"id":"d","text":"Relationship"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Data blending is specifically designed for combining data from multiple separate connections when granularity differences exist. The primary source provides full row-level data while the secondary source contributes aggregates. The source material notes: 'Use blend when relationships or joins don't fit (e.g. different granularities).' A cross-database join would require matching row-level keys and would not handle different granularities gracefully. A union stacks rows of the same structure. A relationship is used within a single data source logical model.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/multiple_connections.htm","label":"Tableau Help – Blend Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P5'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst must combine sales data stored in a SQL Server table with quota data stored in a separate Excel workbook. Both tables share a Region key, but the granularity of the Excel data differs from the SQL Server data. Which Tableau feature is most appropriate for this scenario?$patch$);

