         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/buildexamples_waterfall.htm","label":"Tableau — Build a Waterfall Chart"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
