  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst notices a cell in a blended view displays an asterisk (*) instead of a dimension value. What does this indicate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which of the following file types is supported as a direct file-based connection in Tableau Desktop according to the TDA-C01 blueprint?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"AVRO (.avro)"},{"id":"b","text":"SAS (.sas7bdat)"},{"id":"c","text":"Parquet (.parquet) via native connector"},{"id":"d","text":"XML (.xml) via native connector"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Tableau Desktop supports statistical file formats as direct file-based connections, including SAS (.sas7bdat), SPSS (.sav), and R (.rdata, .rda). The source material lists: 'statistical files (SAS, SPSS, R)' under file-based connections. AVRO and Parquet are not listed as native file-based connectors in the TDA-C01 blueprint; XML does not appear as a native file connector in this scope.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/exampleconnections_overview.htm","label":"Tableau Help – Supported Connectors"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
