  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which of the following file types is supported as a direct file-based connection in Tableau Desktop according to the TDA-C01 blueprint?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$In Tableau's logical layer, two tables are connected using a Relationship rather than a Join. What is a key behavioral difference of Relationships compared to Joins?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Relationships always produce a Full Outer join at query time regardless of context."},{"id":"b","text":"Relationships preserve row context and apply the appropriate join type automatically at query time based on the fields used."},{"id":"c","text":"Relationships are only available when connecting to file-based data sources."},{"id":"d","text":"Relationships require that both tables have exactly the same number of rows."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Relationships are defined in the logical layer of the data model and do not physically merge tables at connection time. Instead, Tableau generates the appropriate join type and aggregation automatically at query time based on which fields are in use, preserving row context and avoiding duplicate rows. The source material states: 'Relationships (new model): logical layer connecting tables; preserves context, automatic aggregation.' None of the distractor behaviors are accurate.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/relate_tables.htm","label":"Tableau Help – Relate Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$In Tableau's logical layer, two tables are connected using a Relationship rather than a Join. What is a key behavioral difference of Relationships compared to Joins?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to combine three annual sales CSV files (sales_2022.csv, sales_2023.csv, sales_2024.csv) that have identical column structures into a single data source. Which feature should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Cross-database join"},{"id":"b","text":"Data blending"},{"id":"c","text":"Union"},{"id":"d","text":"Pivot"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$A Union stacks rows from multiple tables or files that share the same column structure, which is exactly what is needed when combining annual CSV files with identical schemas. The source material states: 'Unions: combine tables with the same columns.' For a known set of named files, a manual union is appropriate. Data blending joins separate connections at the view level. Cross-database joins link tables with different structures. Pivot reshapes column layout.$patch$, $patch$Connect to and Transform Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/union.htm","label":"Tableau Help – Union Your Data"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
