INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$Which Tableau feature allows an end user to input a custom value at runtime that can then be used inside a calculated field or filter without changing the underlying data?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Context Filter"},{"id":"b","text":"Parameter"},{"id":"c","text":"Group"},{"id":"d","text":"Set"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$Parameters are user-editable inputs that can be referenced inside calculated fields, filters, reference lines, and other controls. They allow end users to pass a custom value into the workbook at runtime without modifying the data. Context Filters set a data scope but are not user-editable values. Groups and Sets classify data but are not runtime input mechanisms. The source material explicitly lists 'Parameters (user-editable)' under the Explore and Analyze Data domain.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/parameters_create.htm","label":"Tableau – Create Parameters"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$Which Tableau feature allows an end user to input a custom value at runtime that can then be used inside a calculated field or filter without changing the underlying data?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst adds a trend line to a scatter plot in Tableau. The relationship between variables appears to level off as X increases. Which trend line model is most appropriate?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Linear"},{"id":"b","text":"Logarithmic"},{"id":"c","text":"Polynomial"},{"id":"d","text":"Exponential"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$A logarithmic trend line models relationships where the rate of change decreases as X grows — the curve rises quickly and then levels off, which matches the described pattern. A linear model assumes a constant rate of change. An exponential model assumes accelerating growth. A polynomial model fits curves with multiple inflections. The source material lists logarithmic as one of the available trend line models in the Analytics pane under 'Trend Line (linear, log, exp, polynomial)'.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/trendlines_add.htm","label":"Tableau – Trend Lines"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst adds a trend line to a scatter plot in Tableau. The relationship between variables appears to level off as X increases. Which trend line model is most appropriate?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A calculated field uses { INCLUDE [Product Category] : AVG([Profit]) }. Compared to a view that only has [Region] on Rows, what effect does the INCLUDE LOD expression have?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"It removes [Product Category] from the calculation and computes AVG([Profit]) only at the Region level."},{"id":"b","text":"It forces the calculation to be performed at a finer grain that includes [Product Category], even though [Product Category] is not in the view."},{"id":"c","text":"It excludes [Product Category] from the data source before computing the average."},{"id":"d","text":"It computes the average profit ignoring all dimensions in the view, similar to a FIXED LOD with no dimension."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$INCLUDE LOD expressions add the specified dimension to the level of detail used for the calculation, regardless of whether that dimension appears in the view. So { INCLUDE [Product Category] : AVG([Profit]) } computes the average profit at the Region + Product Category grain and then aggregates back up to Region in the view. It does not remove the dimension (that would be EXCLUDE), nor does it ignore the view entirely (that would be FIXED with no dimension). The source material defines INCLUDE as '{ INCLUDE [dim] : ... }' under Level of Detail expressions.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_calculatedfields_lod.htm","label":"Tableau – Level of Detail Expressions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A calculated field uses { INCLUDE [Product Category] : AVG([Profit]) }. Compared to a view that only has [Region] on Rows, what effect does the INCLUDE LOD expression have?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst uses the SPLIT function on the field [Email] to extract only the domain portion (e.g., 'gmail.com' from 'user@gmail.com'). Which expression is correct?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"SPLIT([Email], '@', 1)"},{"id":"b","text":"SPLIT([Email], '@', 2)"},{"id":"c","text":"SPLIT([Email], '@', -1)"},{"id":"d","text":"SPLIT([Email], '.', 2)"}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$The SPLIT function in Tableau takes the form SPLIT(string, delimiter, token_number). Token 1 is the part before the delimiter ('user') and token 2 is the part after the '@' ('gmail.com'). Therefore SPLIT([Email], '@', 2) extracts the domain. Token 1 would return the username. Token -1 returns the last token from the right which is 'com' not the full domain. Splitting on '.' would not separate username from domain. The source material lists SPLIT under String functions.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_string.htm","label":"Tableau – String Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$An analyst uses the SPLIT function on the field [Email] to extract only the domain portion (e.g., 'gmail.com' from 'user@gmail.com'). Which expression is correct?$patch$);
INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A sales manager wants a Tableau view to automatically predict future monthly revenue based on historical trends. Which Analytics pane feature should the analyst use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"Reference Band"},{"id":"b","text":"Cluster Analysis"},{"id":"c","text":"Forecasting"},{"id":"d","text":"Box Plot"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$Forecasting in Tableau uses exponential smoothing to project future values based on historical patterns, making it the correct tool for predicting future monthly revenue. Reference Bands highlight a range of values but do not predict future data. Cluster Analysis groups data points by similarity (k-means) but does not project into the future. Box Plots summarize distribution statistics. The source material explicitly lists 'Forecasting (exponential smoothing)' under the Analytics pane.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/forecast_how_it_works.htm","label":"Tableau – How Forecasting Works in Tableau"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
