INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$An analyst needs to convert all values in [Country Name] to uppercase for a dashboard filter. Which Tableau function should they use?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"TRIM([Country Name])"},{"id":"b","text":"REPLACE([Country Name], ' ', '_')"},{"id":"c","text":"UPPER([Country Name])"},{"id":"d","text":"CONTAINS([Country Name], 'A')"}]$json$::jsonb, $json$["c"]$json$::jsonb, $patch$UPPER converts all characters in a string to uppercase, which satisfies the requirement. TRIM removes leading and trailing spaces but does not change case. REPLACE substitutes one substring for another and does not affect case. CONTAINS returns a Boolean indicating whether a substring is present, not a transformed string. The source material lists UPPER under String functions in the Explore and Analyze Data domain.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/functions_functions_string.htm","label":"Tableau – String Functions"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
