INSERT INTO "Question" (id, "examId", stem, type, options, correct, explanation, domain, difficulty, "references", status, "generatedBy", "isTeaser", "createdAt", "updatedAt")
  SELECT gen_random_uuid()::text, e.id, $patch$A table calculation is configured to compute a Running Total of Sales. The 'Compute Using' setting is changed from 'Table (Across)' to 'Pane (Down)'. What is the effect of this change?$patch$, 'SINGLE'::"QType",
         $json$[{"id":"a","text":"The running total will restart at the beginning of each row and accumulate across columns within each pane."},{"id":"b","text":"The running total will restart at the top of each pane and accumulate downward within each pane."},{"id":"c","text":"The running total will accumulate across the entire table from left to right, ignoring pane boundaries."},{"id":"d","text":"The running total will be computed independently for each individual cell without any accumulation."}]$json$::jsonb, $json$["b"]$json$::jsonb, $patch$When 'Compute Using' is set to 'Pane (Down)', the running total restarts at the beginning of each pane and accumulates downward through the marks within that pane. 'Table (Across)' accumulates left to right across the entire table regardless of pane boundaries. 'Cell' computes independently per cell with no accumulation. The source material states table calculations can be computed using 'Table (Across/Down), Pane, Cell, or Specific Dimensions', and Pane scoping resets the calculation at each pane boundary.$patch$, $patch$Explore and Analyze Data$patch$,
         3, $json$[{"url":"https://help.tableau.com/current/pro/desktop/en-us/calculations_tablecalculations_definethecomputeusing.htm","label":"Tableau – Table Calculation Scope and Direction"}]$json$::jsonb, 'DRAFT'::"QStatus", 'claude-sonnet-4-6', false, NOW(), NOW()
  FROM "Exam" e WHERE e.code = 'TDA-C01-P6'
  AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $patch$A table calculation is configured to compute a Running Total of Sales. The 'Compute Using' setting is changed from 'Table (Across)' to 'Pane (Down)'. What is the effect of this change?$patch$);

